/**
 * Ley 24.522 (1995) — Concursos y Quiebras. VIGENTE (con reformas: leyes 25.563,
 * 25.589, 26.086, 26.684, entre otras).
 *
 * Fuente oficial (texto actualizado): InfoLeg
 *   http://servicios.infoleg.gob.ar/infolegInternet/anexos/25000-29999/25379/texact.htm
 * Estructura: 4 Títulos · 297 artículos (incluye 32 bis y 45 bis).
 *
 * El TEXTO OFICIAL verbatim de los 298 artículos se genera con
 * scripts/parse-ley24522.mjs a partir del .txt de InfoLeg y vive en
 * ./ley-24522.articulos.ts (RAW_24522). Acá se le agrega título curado +
 * explicación en lenguaje claro (EXPLICACIONES) y la estructura (secciones).
 * Los arts. 1-40 tienen redacción curada a mano (MANUALES); el resto toma el
 * texto del archivo generado.
 *
 * MIGRADA A LA BD (301 arts, 301 segs). Vive en la BD; este archivo es la fuente
 * versionada. Para re-migrar: agregar LEY_24522 a ALL_LAWS en ./index.ts y correr
 * scripts/migrate-norm-to-db.ts, luego revertir index.ts a [].
 */
import type { Law, Article } from '../common/types/law.types';
import { RAW_24522 } from './ley-24522.articulos';

const LAW_ID = 'ley-24522';

function artOrder(number: string): number {
  const m = number.match(/^(\d+)/);
  const base = m ? parseInt(m[1], 10) : 0;
  if (/bis/i.test(number)) return base + 0.33;
  if (/ter/i.test(number)) return base + 0.66;
  return base;
}

function art(number: string, title: string, text: string, explanation: string): Article {
  const id = `${LAW_ID}-art-${number.replace(/\s+/g, '-').toLowerCase()}`;
  return {
    id, lawId: LAW_ID, number, title, text,
    plainLanguageExplanation: explanation,
    practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [],
    regulations: [], keywords: [], order: artOrder(number),
    segments: [{
      id: `${id}-s1`, lawId: LAW_ID, articleId: id, articleNumber: number,
      segmentType: 'PARAGRAPH', text, plainExplanation: explanation,
      practicalExample: null, references: [], order: 0,
    }],
    amendments: [],
  };
}

const MANUALES: Article[] = [
  // ─── TÍTULO I — PRINCIPIOS GENERALES (arts. 1 a 4) ───────────────────────────
  art('1', 'Cesación de pagos. Universalidad',
    `Cesación de pagos. El estado de cesación de pagos, cualquiera sea su causa y la naturaleza de las obligaciones a las que afecte, es presupuesto para la apertura de los concursos regulados en esta ley, sin perjuicio de lo dispuesto por los artículos 66 y 69. Universalidad. El concurso produce sus efectos sobre la totalidad del patrimonio del deudor, salvo las exclusiones legalmente establecidas respecto de bienes determinados.`,
    `Para abrir un concurso o quiebra hace falta que el deudor esté en "cesación de pagos": no poder cumplir de manera regular con sus obligaciones, sea cual sea la causa. Y el concurso es universal: alcanza a todo el patrimonio del deudor, salvo los bienes que la ley excluya expresamente.`),
  art('2', 'Sujetos comprendidos',
    `Sujetos comprendidos. Pueden ser declaradas en concurso las personas de existencia visible, las de existencia ideal de carácter privado y aquellas sociedades en las que el Estado Nacional, Provincial o Municipal sea parte, cualquiera sea el porcentaje de su participación. Se consideran comprendidos: 1) El patrimonio del fallecido, mientras se mantenga separado del patrimonio de los sucesores. 2) Los deudores domiciliados en el extranjero respecto de bienes existentes en el país. No son susceptibles de ser declaradas en concurso, las personas reguladas por Leyes Nros. 20.091, 20.321 y 24.241, así como las excluidas por leyes especiales.`,
    `Quiénes pueden concursarse o quebrar: personas humanas, personas jurídicas privadas (empresas, sociedades, asociaciones) y sociedades con participación estatal. También el patrimonio de un fallecido (mientras no se mezcle con el de los herederos) y deudores del exterior por sus bienes en el país. Quedan afuera las aseguradoras, mutuales y las AFJP, y otras excluidas por leyes especiales.`),
  art('3', 'Juez competente',
    `Juez competente. Corresponde intervenir en los concursos al juez con competencia ordinaria, de acuerdo a las siguientes reglas: 1) Si se trata de personas de existencia visible, al del lugar de la sede de la administración de sus negocios; a falta de éste, al del lugar del domicilio. 2) Si el deudor tuviere varias administraciones es competente el juez del lugar de la sede de la administración del establecimiento principal; si no pudiere determinarse esta calidad, lo que es el juez que hubiere prevenido. 3) En caso de concurso de personas de existencia ideal de carácter privado regularmente constituidas, y las sociedades en que el Estado Nacional, Provincial o Municipal sea parte —con las exclusiones previstas en el Artículo 2— entiende el juez del lugar del domicilio. 4) En el caso de sociedades no constituidas regularmente, entiende el juez del lugar de la sede; en su defecto, el del lugar del establecimiento o explotación principal. 5) Tratándose de deudores domiciliados en el exterior, el juez del lugar de la administración en el país; a falta de éste, entiende el del lugar del establecimiento, explotación o actividad principal, según el caso.`,
    `Define qué juez interviene en cada caso. En general: para personas humanas, el del lugar donde administran sus negocios o, si no, su domicilio; para empresas regulares, el de su domicilio social; para sociedades irregulares, el de su sede o explotación principal; y para deudores del exterior, el del lugar de su administración o actividad en el país.`),
  art('4', 'Concursos declarados en el extranjero',
    `Concursos declarados en el extranjero. La declaración de concurso en el extranjero es causal para la apertura del concurso en el país, a pedido del deudor o del acreedor cuyo crédito debe hacerse efectivo en la REPUBLICA ARGENTINA. Sin perjuicio de lo dispuesto en los tratados internacionales, el concurso en el extranjero, no puede ser invocado contra los acreedores cuyos créditos deban ser pagados en la REPUBLICA ARGENTINA, para disputarles derechos que éstos pretenden sobre los bienes existentes en el territorio ni para anular los actos que hayan celebrado con el concursado. Pluralidad de concursos. Declarada también la quiebra en el país, los acreedores pertenecientes al concurso formado en el extranjero actuarán sobre el saldo, una vez satisfechos los demás créditos verificados en aquélla. Reciprocidad. La verificación del acreedor cuyo crédito es pagadero en el extranjero, y que no pertenezca a un concurso abierto en el exterior, está condicionada a que se demuestre que, recíprocamente, un acreedor cuyo crédito es pagadero en la REPUBLICA ARGENTINA puede verificarse y cobrar —en iguales condiciones— en un concurso abierto en el país en el cual aquel crédito es pagadero. Paridad en los dividendos. Los cobros de créditos quirografarios con posterioridad a la apertura del concurso nacional, efectuados en el extranjero, serán imputados al dividendo correspondiente a sus beneficiarios por causas de créditos comunes. Quedan exceptuados de acreditar la reciprocidad los titulares de créditos con garantía real.`,
    `Regula los concursos con elementos en el extranjero. Un concurso abierto afuera permite abrir uno en Argentina. Pero ese concurso extranjero no puede usarse contra los acreedores que cobran en el país. Los acreedores del concurso extranjero solo cobran sobre el saldo que quede acá. Y el acreedor cuyo crédito se paga afuera debe probar "reciprocidad" (que un acreedor argentino podría cobrar allá en iguales condiciones), salvo que tenga garantía real (hipoteca o prenda).`),

  // ─── TÍTULO II — CONCURSO PREVENTIVO ─────────────────────────────────────────
  // CAPÍTULO I — Requisitos (arts. 5 a 12)
  art('5', 'Sujetos',
    `Sujetos. Pueden solicitar la formación de su concurso preventivo las personas comprendidas en el Artículo 2, incluidas las de existencia ideal en liquidación.`,
    `Puede pedir su propio concurso preventivo cualquiera de los sujetos que pueden concursarse (art. 2), incluso una sociedad que ya esté en proceso de liquidación.`),
  art('6', 'Personas de existencia ideal: representación y ratificación',
    `Personas de existencia ideal. Representación y ratificación. Tratándose de personas de existencia ideal, privadas o públicas, lo solicita el representante legal, previa resolución, en su caso, del órgano de administración. Dentro de los TREINTA (30) días de la fecha de la presentación, deben acompañar constancia de la resolución de continuar el trámite, adoptada por la asamblea, reunión de socios u órgano de gobierno que corresponda, con las mayorías necesarias para resolver asuntos ordinarios. No acreditado este requisito, se produce de pleno derecho la cesación del procedimiento, con los efectos del desistimiento de la petición.`,
    `Cuando concursa una sociedad, lo pide su representante legal (con decisión previa del directorio si corresponde). Después tiene 30 días para acompañar la decisión del órgano de gobierno (asamblea o reunión de socios) ratificando que se sigue adelante. Si no lo hace, el concurso se cae solo, como si lo hubiera abandonado.`),
  art('7', 'Incapaces e inhabilitados',
    `Incapaces e inhabilitados. En casos de incapaces o inhabilitados, la solicitud debe ser efectuada por sus representantes legales y ratificada, en su caso, por el juez que corresponda, dentro de los TREINTA (30) días contados desde la presentación. La falta de ratificación produce los efectos indicados en el último párrafo del artículo anterior.`,
    `Si el deudor es un incapaz o inhabilitado, el concurso lo pide su representante legal y debe ratificarlo el juez que corresponda dentro de los 30 días. Sin esa ratificación, el trámite se cae (como en el art. 6).`),
  art('8', 'Personas fallecidas',
    `Personas fallecidas. Mientras se mantenga la separación patrimonial, cualquiera de los herederos puede solicitar el concurso preventivo en relación al patrimonio del fallecido. La petición debe ser ratificada por los demás herederos, dentro de los TREINTA (30) días. Omitida la ratificación, se aplica el último párrafo del Artículo 6.`,
    `Se puede concursar el patrimonio de una persona fallecida mientras siga separado del de los herederos. Lo pide cualquier heredero, y los demás deben ratificarlo en 30 días; si no, el trámite se cae.`),
  art('9', 'Representación voluntaria',
    `Representación voluntaria. La apertura del concurso preventivo puede ser solicitada, también por apoderado con facultad especial.`,
    `El concurso también puede pedirlo un apoderado, siempre que tenga un poder con facultad especial para ese acto (no alcanza un poder general).`),
  art('10', 'Oportunidad de la presentación',
    `Oportunidad de la presentación. El concurso preventivo puede ser solicitado mientras la quiebra no haya sido declarada.`,
    `Se puede pedir el concurso preventivo en cualquier momento, siempre que todavía no se haya declarado la quiebra.`),
  art('11', 'Requisitos del pedido',
    `Requisitos del pedido. Son requisitos formales de la petición de concurso preventivo: 1) Para los deudores matriculados y las personas de existencia ideal regularmente constituidas, acreditar la inscripción en los registros respectivos. Las últimas acompañarán, además, el instrumento constitutivo y sus modificaciones y constancia de las inscripciones pertinentes. Para las demás personas de existencia ideal, acompañar, en su caso, los instrumentos constitutivos y sus modificaciones, aun cuando no estuvieran inscriptos. 2) Explicar las causas concretas de su situación patrimonial con expresión de la época en que se produjo la cesación de pagos y de los hechos por los cuales ésta se hubiera manifestado. 3) Acompañar un estado detallado y valorado del activo y pasivo actualizado a la fecha de presentación, con indicación precisa de su composición, las normas seguidas para su valuación, la ubicación, estado y gravámenes de los bienes y demás datos necesarios para conocer debidamente el patrimonio. Este estado de situación patrimonial debe ser acompañado de dictamen suscripto por contador público nacional. 4) Acompañar copia de los balances u otros estados contables exigidos al deudor por las disposiciones legales que rijan su actividad, o bien los previstos en sus estatutos o realizados voluntariamente por el concursado, correspondientes a los TRES (3) últimos ejercicios. En su caso, se deben agregar las memorias y los informes del órgano fiscalizador. 5) Acompañar nómina de acreedores, con indicación de sus domicilios, montos de los créditos, causas, vencimientos, codeudores, fiadores o terceros obligados o responsables y privilegios. Asimismo, debe acompañar un legajo por cada acreedor, en el cual conste copia de la documentación sustentatoria de la deuda denunciada, con dictamen de contador público sobre la correspondencia existente entre la denuncia del deudor y sus registros contables o documentación existente y la inexistencia de otros acreedores en registros o documentación existente. Debe agregar el detalle de los procesos judiciales o administrativos de carácter patrimonial en trámite o con condena no cumplida, precisando su radicación. 6) Enumerar precisamente los libros de comercio y los de otra naturaleza que lleve el deudor, con expresión del último folio utilizado, en cada caso, y ponerlos a disposición del juez, junto con la documentación respectiva. 7) Denunciar la existencia de un concurso anterior y justificar, en su caso, que no se encuentra dentro del período de inhibición que establece el artículo 59, o el desistimiento del concurso si lo hubiere habido. 8) Acompañar nómina de empleados, con detalle de domicilio, categoría, antigüedad y última remuneración recibida. Deberá acompañarse también declaración sobre la existencia de deuda laboral y de deuda con los organismos de la seguridad social certificada por contador público. El escrito y la documentación agregada deben acompañarse con DOS (2) copias firmadas. Cuando se invoque causal debida y válidamente fundada, el juez debe conceder un plazo improrrogable de DIEZ (10) días, a partir de la fecha de la presentación, para que el interesado dé cumplimiento total a las disposiciones del presente artículo.`,
    `Es el "checklist" de lo que hay que presentar para pedir el concurso preventivo: acreditar la inscripción registral y el estatuto; explicar las causas y la fecha de la cesación de pagos; un estado de activo y pasivo con dictamen de contador; los balances de los últimos 3 ejercicios; la lista de acreedores con un legajo por cada uno; el detalle de los libros contables; denunciar concursos anteriores; y la nómina de empleados con la deuda laboral y previsional. Todo por duplicado. Si falta algo y hay causa válida, el juez puede dar 10 días improrrogables para completarlo.`),
  art('12', 'Domicilio procesal',
    `Domicilio procesal. El concursado y, en su caso, los administradores y los socios con responsabilidad ilimitada, deben constituir domicilio procesal en el lugar de tramitación del juicio. De no hacerlo en la primera presentación, se lo tendrá por constituido en los estados del juzgado, para todos los efectos del concurso.`,
    `El concursado (y sus administradores y socios ilimitadamente responsables) debe fijar un domicilio procesal en la ciudad donde tramita el juicio. Si no lo hace en su primer escrito, todas las notificaciones se tienen por hechas en el juzgado (queda "notificado por nota").`),

  // CAPÍTULO II — Apertura (arts. 13 a 25)
  art('13', 'Término. Rechazo',
    `Término. Presentado el pedido o, en su caso, vencido el plazo que acuerde el juez, éste se debe pronunciar dentro del término de CINCO (5) días. Rechazo. Debe rechazar la petición, cuando el deudor no sea sujeto susceptible de concurso preventivo, si no se ha dado cumplimiento al artículo 11, si se encuentra dentro del período de inhibición que establece el artículo 59, o cuando la causa no sea de su competencia. La resolución es apelable.`,
    `Presentado el pedido, el juez tiene 5 días para resolver. Debe rechazarlo si el deudor no puede concursarse, si no cumplió los requisitos del art. 11, si está dentro del período de inhibición (art. 59) o si el caso no es de su competencia. El rechazo se puede apelar.`),
  art('14', 'Resolución de apertura. Contenido',
    `Resolución de apertura. Contenido. Cumplidos en debido tiempo los requisitos legales, el juez debe dictar resolución que disponga: 1) La declaración de apertura del concurso preventivo, expresando el nombre del concursado y, en su caso, el de los socios con responsabilidad ilimitada. 2) La designación de audiencia para el sorteo del síndico. 3) La fijación de una fecha hasta la cual los acreedores deben presentar sus pedidos de verificación al síndico, la que debe estar comprendida entre los QUINCE (15) y los VEINTE (20) días, contados desde el día en que se estime concluirá la publicación de los edictos. 4) La orden de publicar edictos en la forma prevista por los artículos 27 y 28, la designación de los diarios respectivos y, en su caso, la disposición de las rogatorias necesarias. 5) La determinación de un plazo no superior a los TRES (3) días, para que el deudor presente los libros que lleve referidos a su situación económica, en el lugar que el juez fije dentro de su jurisdicción, con el objeto de que el secretario coloque nota datada a continuación del último asiento, y proceda a cerrar los espacios en blanco que existieran. 6) La orden de anotar la apertura del concurso en el Registro de Concursos y en los demás que corresponda, requiriéndose informe sobre la existencia de otros anteriores. 7) La inhibición general para disponer y gravar bienes registrables del deudor y, en su caso, los de los socios ilimitadamente responsables, debiendo ser anotadas en los registros pertinentes. 8) La intimación al deudor para que deposite judicialmente, dentro de los TRES (3) días de notificada la resolución, el importe que el juez estime necesario para abonar los gastos de correspondencia. 9) Las fechas en que el síndico deberá presentar el informe individual de los créditos y el informe general. 10) La fijación de una audiencia informativa que se realizará con cinco (5) días de anticipación al vencimiento del plazo de exclusividad previsto en el artículo 43. Dicha audiencia deberá ser notificada a los trabajadores del deudor mediante su publicación por medios visibles en todos sus establecimientos. 11) Correr vista al síndico por el plazo de diez (10) días, el que se computará a partir de la aceptación del cargo, a fin de que se pronuncie sobre: a) Los pasivos laborales denunciados por el deudor; b) Previa auditoría en la documentación legal y contable, informe sobre la existencia de otros créditos laborales comprendidos en el pronto pago. 12) El síndico deberá emitir un informe mensual sobre la evolución de la empresa, si existen fondos líquidos disponibles y el cumplimiento de las normas legales y fiscales. 13) La constitución de un comité de control, integrado por los tres (3) acreedores quirografarios de mayor monto, denunciados por el deudor y un (1) representante de los trabajadores de la concursada, elegido por los trabajadores.`,
    `Es el "auto de apertura": la resolución con la que el juez abre el concurso y fija toda la hoja de ruta. Entre otras cosas: declara abierto el concurso, ordena sortear al síndico, fija la fecha tope para que los acreedores pidan la verificación (entre 15 y 20 días tras los edictos), manda publicar edictos, inhibe al deudor para vender o gravar bienes registrables, fija las fechas de los informes del síndico, ordena una audiencia informativa antes del fin del período de exclusividad, y constituye el comité de control (3 acreedores y 1 representante de los trabajadores).`),
  art('15', 'Administración del concursado',
    `Administración del concursado. El concursado conserva la administración de su patrimonio bajo la vigilancia del síndico.`,
    `En el concurso preventivo el deudor NO pierde el manejo de sus bienes: sigue administrando su patrimonio, pero bajo la vigilancia del síndico. (Es la gran diferencia con la quiebra, donde sí se lo desapodera.)`),
  art('16', 'Actos prohibidos. Pronto pago de créditos laborales. Actos sujetos a autorización',
    `Actos prohibidos. El concursado no puede realizar actos a título gratuito o que importen alterar la situación de los acreedores por causa o título anterior a la presentación. Pronto pago de créditos laborales. Dentro del plazo de diez (10) días de emitido el informe que establece el artículo 14 inciso 11), el juez del concurso autorizará el pago de las remuneraciones debidas al trabajador, las indemnizaciones por accidentes de trabajo o enfermedades laborales y las previstas en los artículos 132 bis, 212, 232, 233 y 245 a 254, 178, 180 y 182 del Régimen de Contrato de Trabajo aprobado por la ley 20.744; las indemnizaciones previstas en la ley 25.877, en los artículos 1º y 2º de la ley 25.323; en los artículos 8º, 9º, 10, 11 y 15 de la ley 24.013; en el artículo 44 y 45 de la ley 25.345; en el artículo 52 de la ley 23.551; y las previstas en los estatutos especiales, convenios colectivos o contratos individuales, que gocen de privilegio general o especial y que surjan del informe mencionado en el inciso 11 del artículo 14. Para que proceda el pronto pago de crédito no incluido en el listado que establece el artículo 14 inciso 11), no es necesaria la verificación del crédito en el concurso ni sentencia en juicio laboral previo. Previa vista al síndico y al concursado, el juez podrá denegar total o parcialmente el pedido de pronto pago mediante resolución fundada, sólo cuando existiere duda sobre su origen o legitimidad, se encontraren controvertidos o existiere sospecha de connivencia entre el peticionario y el concursado. En todos los casos la decisión será apelable. La resolución judicial que admite el pronto pago tendrá efectos de cosa juzgada material e importará la verificación del crédito en el pasivo concursal. La que lo deniegue, habilitará al acreedor para iniciar o continuar el juicio de conocimiento laboral ante el juez natural. No se impondrán costas al trabajador en la solicitud de pronto pago, excepto en el caso de connivencia, temeridad o malicia. Los créditos serán abonados en su totalidad, si existieran fondos líquidos disponibles. En caso contrario y hasta que se detecte la existencia de los mismos por parte del síndico se deberá afectar el tres por ciento (3%) mensual del ingreso bruto de la concursada. El síndico efectuará un plan de pago proporcional a los créditos y sus privilegios, no pudiendo exceder cada pago individual en cada distribución un monto equivalente a cuatro (4) salarios mínimos vitales y móviles. Excepcionalmente el juez podrá autorizar, dentro del régimen de pronto pago, el pago de aquellos créditos amparados por el beneficio y que, por su naturaleza o circunstancias particulares de sus titulares, deban ser afectados a cubrir contingencias de salud, alimentarias u otras que no admitieran demoras. En el control e informe mensual, que la sindicatura deberá realizar, incluirá las modificaciones necesarias, si existen fondos líquidos disponibles, a los efectos de abonar la totalidad de los prontos pagos o modificar el plan presentado. Actos sujetos a autorización. Debe requerir previa autorización judicial para realizar cualquiera de los siguientes actos: los relacionados con bienes registrables; los de disposición o locación de fondos de comercio; los de emisión de debentures con garantía especial o flotante; los de emisión de obligaciones negociables con garantía especial o flotante; los de constitución de prenda y los que excedan de la administración ordinaria de su giro comercial. La autorización se tramita con audiencia del síndico y del comité de control; para su otorgamiento el juez ha de ponderar la conveniencia para la continuación de las actividades del concursado y la protección de los intereses de los acreedores.`,
    `Marca los límites de lo que el deudor puede hacer durante el concurso. No puede hacer actos gratuitos ni favorecer a unos acreedores por deudas anteriores. Regula el "pronto pago laboral": el juez autoriza pagar sueldos e indemnizaciones de los trabajadores con prioridad y sin necesidad de verificar el crédito; si no hay fondos, se destina el 3% mensual del ingreso bruto de la empresa, con un tope por pago de 4 salarios mínimos. Y enumera los actos importantes (vender bienes registrables, el fondo de comercio, constituir prendas, etc.) que el deudor solo puede hacer con autorización del juez.`),
  art('17', 'Actos ineficaces. Separación de la administración',
    `Actos ineficaces. Los actos cumplidos en violación a lo dispuesto en el Artículo 16 son ineficaces de pleno derecho respecto de los acreedores. Separación de la administración. Además, cuando el deudor contravenga lo establecido en los Artículos 16 y 25 o cuando oculte bienes, omita las informaciones que el juez o el síndico le requieran, incurra en falsedad en las que produzca o realice algún acto en perjuicio evidente para los acreedores, el juez puede separarlo de la administración por auto fundado y designar reemplazante. Esta resolución es apelable al solo efecto devolutivo, por el deudor. Si se deniega la medida puede apelar el síndico. El administrador debe obrar según lo dispuesto en los artículos 15 y 16. Limitación. De acuerdo con las circunstancias del caso, el juez puede limitar la medida a la designación de un coadministrador, un veedor o un interventor controlador, con las facultades que disponga. La providencia es apelable en las condiciones indicadas en el segundo párrafo. En todos los casos, el deudor conserva en forma exclusiva la legitimación para obrar, en los actos del juicio que, según esta ley, correspondan al concursado.`,
    `Si el deudor hace alguno de los actos prohibidos del art. 16, esos actos no valen frente a los acreedores. Y si además oculta bienes, miente, no informa o perjudica claramente a los acreedores, el juez puede sacarle la administración y nombrar a otro, o medidas más suaves (un coadministrador, veedor o interventor). El deudor conserva igual la legitimación para actuar en el juicio.`),
  art('18', 'Socio con responsabilidad ilimitada',
    `Socio con responsabilidad ilimitada. Efectos. Las disposiciones de los artículos 16 y 17 se aplican respecto del patrimonio de los socios con responsabilidad ilimitada de las sociedades concursadas.`,
    `Las prohibiciones y controles de los arts. 16 y 17 también alcanzan al patrimonio personal de los socios que responden de forma ilimitada por las deudas de la sociedad concursada.`),
  art('19', 'Intereses. Deudas no dinerarias',
    `Intereses. La presentación del concurso produce la suspensión de los intereses que devengue todo crédito de causa o título anterior a ella, que no esté garantizado con prenda o hipoteca. Los intereses de los créditos así garantizados, posteriores a la presentación, sólo pueden ser reclamados sobre las cantidades provenientes de los bienes afectados a la hipoteca o a la prenda. Deudas no dinerarias. Las deudas no dinerarias son convertidas, a todos los fines del concurso, a su valor en moneda de curso legal, al día de la presentación o al del vencimiento, si fuere anterior, a opción del acreedor. Las deudas en moneda extranjera se calculan en moneda de curso legal, a la fecha de la presentación del informe del síndico previsto en el artículo 35, al solo efecto del cómputo del pasivo y de las mayorías. Quedan excluidos de la disposición precedente los créditos laborales correspondientes a la falta de pago de salarios y toda indemnización derivada de la relación laboral.`,
    `Al presentarse el concurso se "congelan" los intereses de las deudas anteriores, salvo las que tengan hipoteca o prenda (esos intereses solo se cobran sobre el bien garantizado). Las deudas que no son en dinero y las que están en moneda extranjera se convierten a pesos para calcular el pasivo y las mayorías. Quedan afuera de esta conversión los créditos laborales por salarios e indemnizaciones.`),
  art('20', 'Contratos con prestación recíproca pendiente. Servicios públicos',
    `Contratos con prestación recíproca pendiente. El deudor puede continuar con el cumplimiento de los contratos en curso de ejecución, cuando hubiere prestaciones recíprocas pendientes. Para ello debe requerir autorización del juez, quien resuelve previa vista al síndico. La continuación del contrato autoriza al cocontratante a exigir el cumplimiento de las prestaciones adeudadas a la fecha de presentación en concurso bajo apercibimiento de resolución. Las prestaciones que el tercero cumpla después de la presentación en concurso preventivo, y previo cumplimiento de lo dispuesto en este precepto, gozan del privilegio previsto por el artículo 240. La tradición simbólica anterior a la presentación, no importa cumplimiento de la prestación a los fines de este artículo. Sin perjuicio de la aplicación del artículo 753 del Código Civil, el tercero puede resolver el contrato cuando no se le hubiere comunicado la decisión de continuarlo, luego de los treinta (30) días de abierto el concurso. Debe notificar al deudor y al síndico. Servicios públicos. No pueden suspenderse los servicios públicos que se presten al deudor por deudas con origen en fecha anterior a la de la apertura del concurso. Los servicios prestados con posterioridad a la apertura del concurso deben abonarse a sus respectivos vencimientos y pueden suspenderse en caso de incumplimiento mediante el procedimiento previsto en las normas que rigen sus respectivas prestaciones. En caso de liquidación en la quiebra, los créditos que se generen por las prestaciones mencionadas en el párrafo anterior gozan de la preferencia establecida por el artículo 240.`,
    `El deudor puede seguir con los contratos en marcha (los que tienen prestaciones pendientes de ambos lados), pidiendo autorización al juez. Si los continúa, debe ponerse al día con lo adeudado y lo nuevo que el otro entregue cobra con privilegio. Importante: no se le pueden cortar los servicios públicos (luz, gas, agua) por deudas anteriores al concurso; sí por las posteriores impagas.`),
  art('21', 'Juicios contra el concursado',
    `Juicios contra el concursado. La apertura del concurso produce, a partir de la publicación de edictos, la suspensión del trámite de los juicios de contenido patrimonial contra el concursado por causa o título anterior a su presentación, y su radicación en el juzgado del concurso. No podrán deducirse nuevas acciones con fundamento en tales causas o títulos. Quedan excluidos de los efectos antes mencionados: 1. Los procesos de expropiación, los que se funden en las relaciones de familia y las ejecuciones de garantías reales; 2. Los procesos de conocimiento en trámite y los juicios laborales, salvo que el actor opte por suspender el procedimiento y verificar su crédito conforme lo dispuesto por los artículos 32 y concordantes; 3. Los procesos en los que el concursado sea parte de un litis consorcio pasivo necesario. 4. Los procesos de extinción de dominio. En estos casos los juicios proseguirán ante el tribunal de su radicación originaria o ante el que resulte competente si se trata de acciones laborales nuevas. El síndico será parte necesaria en tales juicios, excepto en los que se funden en relaciones de familia, a cuyo efecto podrá otorgar poder a favor de abogados cuya regulación de honorarios estará a cargo del juez del concurso, cuando el concursado resultare condenado en costas, y se regirá por las pautas previstas en la presente ley. En los procesos indicados en los incisos 2) y 3) no procederá el dictado de medidas cautelares. Las que se hubieren ordenado, serán levantadas por el juez del concurso, previa vista a los interesados. La sentencia que se dicte en los mismos valdrá como título verificatorio en el concurso. En las ejecuciones de garantías reales no se admitirá el remate de la cosa gravada ni la adopción de medidas precautorias que impidan su uso por el deudor, si no se acredita haber presentado el pedido de verificación del crédito y su privilegio.`,
    `Es el "fuero de atracción": al abrirse el concurso, los juicios de plata contra el deudor por deudas anteriores se suspenden y pasan al juzgado del concurso, y no se pueden iniciar nuevos. Hay excepciones que siguen en su tribunal: expropiaciones, juicios de familia, ejecuciones de hipoteca/prenda, juicios de conocimiento y laborales en trámite, y litisconsorcios. En esos casos el síndico interviene y la sentencia sirve como título para verificar el crédito.`),
  art('22', 'Estipulaciones nulas',
    `Estipulaciones nulas. Son nulas las estipulaciones contrarias a lo dispuesto en los artículos 20 y 21.`,
    `Cualquier cláusula contractual que contradiga las reglas de los arts. 20 y 21 (continuación de contratos y suspensión de juicios) es nula: no se puede pactar en contra de estas protecciones del concurso.`),
  art('23', 'Ejecuciones por remate no judicial',
    `Ejecuciones por remate no judicial. Los acreedores titulares de créditos con garantía real que tengan derecho a ejecutar mediante remate no judicial bienes de la concursada o, en su caso, de los socios con responsabilidad ilimitada, deben rendir cuentas en el concurso acompañando los títulos de sus créditos y los comprobantes respectivos, dentro de los VEINTE (20) días de haberse realizado el remate. El acreedor pierde a favor del concurso, el UNO POR CIENTO (1%) del monto de su crédito, por cada día de retardo, si ha mediado intimación judicial anterior. El remanente debe ser depositado, una vez cubiertos los créditos, en el plazo que el juez fije. Si hubiera comenzado la publicación de los edictos que determina el artículo 27, antes de la publicación de los avisos del remate no judicial, el acreedor debe presentarse al juez del concurso comunicando la fecha, lugar, día y hora fijados para el remate, y el bien a rematar, acompañando, además, el título de su crédito. La omisión de esta comunicación previa vicia de nulidad al remate. La rendición de cuentas debe sustanciarse por incidentes con intervención del concursado y del síndico.`,
    `Los acreedores con garantía real que pueden rematar bienes por su cuenta (sin juicio) deben rendir cuentas en el concurso dentro de los 20 días del remate, y depositar lo que sobre tras cobrarse. Si se demoran tras una intimación, pierden 1% del crédito por día. Si ya empezaron los edictos del concurso, deben avisar al juez antes del remate, bajo pena de nulidad.`),
  art('24', 'Suspensión de remates y medidas precautorias',
    `Suspensión de remates y medidas precautorias. En caso de necesidad y urgencia evidentes para el concurso, y con el criterio del artículo 16, párrafo final, el juez puede ordenar la suspensión temporaria de la subasta y de las medidas precautorias que impidan el uso por el deudor de la cosa gravada, en la ejecución de créditos con garantía prendaria o hipotecaria. Los servicios de intereses posteriores a la suspensión son pagados como los gastos del concurso, si resultare insuficiente el producido del bien gravado. Esta suspensión no puede exceder de NOVENTA (90) días. La resolución es apelable al solo efecto devolutivo por el acreedor, el deudor y el síndico.`,
    `Cuando es urgente para el concurso, el juez puede frenar temporalmente un remate o levantar medidas que impidan al deudor usar un bien hipotecado o prendado, por un máximo de 90 días. Sirve para no paralizar la actividad de la empresa mientras se negocia.`),
  art('25', 'Viaje al exterior',
    `Viaje al exterior. El concursado y, en su caso, los administradores y socios con responsabilidad ilimitada de la sociedad concursada, no pueden viajar al exterior sin previa comunicación al juez del concurso, haciendo saber el plazo de la ausencia, el que no podrá ser superior a CUARENTA (40) días corridos. En caso de ausencia por plazos mayores, deberá requerir autorización judicial.`,
    `El deudor (y los administradores y socios ilimitados) no puede salir del país sin avisar antes al juez del concurso. Si el viaje es de más de 40 días corridos, necesita autorización judicial.`),

  // CAPÍTULO III — Trámite hasta el acuerdo (arts. 26 a 40)
  art('26', 'Regla general de notificaciones',
    `Regla general. Desde la presentación del pedido de formación de concurso preventivo, el deudor o sus representantes deben comparecer en secretaría los días de notificaciones. Todas las providencias se consideran notificadas por ministerio de la ley, salvo que el compareciente deje constancia de su presencia y de no haber podido revisar el expediente, en el correspondiente libro de secretaría.`,
    `Durante el concurso, las resoluciones se notifican automáticamente ("por ministerio de la ley") los días de nota: el deudor debe ir a la secretaría a revisar el expediente, salvo que deje constancia de que fue y no pudo verlo.`),
  art('27', 'Edictos',
    `Edictos. La resolución de apertura del concurso preventivo se hace conocer mediante edictos que deben publicarse durante CINCO (5) días en el diario de publicaciones legales de la jurisdicción del juzgado, y en otro diario de amplia circulación en el lugar del domicilio del deudor, que el juez designe. Los edictos deben contener los datos referentes a la identificación del deudor y de los socios ilimitadamente responsables; los del juicio y su radicación; el nombre y domicilio del síndico, la intimación a los acreedores para que formulen sus pedidos de verificación y el plazo y domicilio para hacerlo. Esta publicación está a cargo del deudor y debe realizarse dentro de los CINCO (5) días de haberse notificado la resolución.`,
    `La apertura del concurso se publica en edictos por 5 días (en el boletín de publicaciones legales y en un diario de amplia circulación) para que todos los acreedores se enteren. Los edictos identifican al deudor, al síndico y el plazo y lugar para pedir la verificación. Los paga el deudor.`),
  art('28', 'Establecimientos en otra jurisdicción',
    `Establecimientos en otra jurisdicción. Cuando el deudor tuviere establecimientos en otra jurisdicción judicial, también se deben publicar edictos por CINCO (5) días, en el lugar de ubicación de cada uno de ellos y, en su caso, en el diario de publicaciones legales respectivo. El juez debe fijar el plazo para que el deudor efectúe estas publicaciones, el cual no puede exceder de VEINTE (20) días, desde la notificación del auto de apertura. Justificación. En todos los casos, el deudor debe justificar el cumplimiento de las publicaciones, mediante la presentación de los recibos, dentro de los plazos indicados; también debe probar la efectiva publicación de los edictos, dentro del quinto día posterior a su primera aparición.`,
    `Si el deudor tiene establecimientos en otras provincias, también debe publicar edictos allí (por 5 días), dentro del plazo que fije el juez (máximo 20 días). Y debe acreditar ante el juzgado que las publicaciones efectivamente se hicieron.`),
  art('29', 'Carta a los acreedores e integrantes del comité de control',
    `Carta a los acreedores e integrantes del comité de control. Sin perjuicio de lo dispuesto en los artículos 27 y 28, el síndico debe enviar a cada acreedor denunciado y a los miembros del comité de control, carta certificada en la cual le haga conocer la apertura del concurso, incluyendo los datos sucintos de los requisitos establecidos en los incisos 1 y 3 del artículo 14, su nombre y domicilio y las horas de atención, la designación del juzgado y secretaría actuantes y su ubicación y los demás aspectos que estime de interés para los acreedores. La correspondencia debe ser remitida dentro de los cinco (5) días de la primera publicación de edictos. La omisión en que incurra el síndico, respecto del envío de las cartas, no invalida el proceso.`,
    `Además de los edictos, el síndico debe avisar por carta certificada a cada acreedor conocido y a los miembros del comité de control, contándoles que se abrió el concurso, sus datos y horarios de atención. Si el síndico no manda alguna carta, el proceso igual sigue siendo válido.`),
  art('30', 'Sanción (desistimiento por incumplimiento)',
    `Sanción. En caso de que el deudor no cumpla lo dispuesto en los incisos 5 y 8 del artículo 14 y en los artículos 27 y 28 primer párrafo, se lo tiene por desistido.`,
    `Si el deudor no cumple ciertas cargas (presentar los libros, depositar los gastos, publicar los edictos), se lo considera "desistido": el concurso se cae por su propia inacción.`),
  art('31', 'Desistimiento voluntario. Inadmisibilidad',
    `Desistimiento voluntario. El deudor puede desistir de su petición hasta la primera publicación de edictos, sin requerir conformidad de sus acreedores. Puede desistir, igualmente, hasta el día indicado para el comienzo del período de exclusividad previsto en el artículo 43 si, con su petición, agrega constancia de la conformidad de la mayoría de los acreedores quirografarios que representen el SETENTA Y CINCO POR CIENTO (75%) del capital quirografario. Para el cálculo de estas mayorías se tienen en cuenta, según el estado de la causa: a los acreedores denunciados con más los presentados a verificar, si el desistimiento ocurre antes de la presentación del informe del artículo 35; después de presentado dicho informe, se consideran los aconsejados a verificar por el síndico; una vez dictada la sentencia prevista en el artículo 36, deberán reunirse las mayorías sobre los créditos de los acreedores verificados o declarados admisibles por el juez. Si el juez desestima una petición de desistimiento por no contar con suficiente conformidad de acreedores, pero después ésta resultare reunida, sea por efecto de las decisiones sobre la verificación o por nuevas adhesiones, hará lugar al desistimiento, y declarará concluido el concurso preventivo. Inadmisibilidad. Rechazada, desistida o no ratificada una petición de concurso preventivo, las que se presenten dentro del año posterior no deben ser admitidas, si existen pedidos de quiebra pendientes.`,
    `El deudor puede retirarse del concurso libremente hasta la primera publicación de edictos. Después, solo puede desistir hasta el inicio del período de exclusividad y con la conformidad del 75% del capital quirografario. Y si su concurso fue rechazado o desistido, no puede volver a presentar otro dentro del año si hay pedidos de quiebra pendientes (evita usar el concurso como maniobra dilatoria).`),

  // SECCIÓN III — Proceso de verificación
  art('32', 'Solicitud de verificación',
    `Solicitud de verificación. Todos los acreedores por causa o título anterior a la presentación y sus garantes, deben formular al síndico el pedido de verificación de sus créditos, indicando monto, causa y privilegios. La petición debe hacerse por escrito, en duplicado, acompañando los títulos justificativos, con dos (2) copias firmadas y debe expresar el domicilio que constituya a todos los efectos del juicio. El síndico devuelve los títulos originales, dejando en ellos constancia del pedido de verificación y su fecha. Puede requerir la presentación de los originales cuando lo estime conveniente. La omisión de presentarlos obsta a la verificación. Efectos: El pedido de verificación produce los efectos de la demanda judicial, interrumpe la prescripción e impide la caducidad del derecho y de la instancia. Arancel: Por cada solicitud de verificación de crédito que se presente, el acreedor, sea tempestivo, incidental o tardío, pagará al síndico un arancel equivalente al diez por ciento (10%) del salario mínimo vital y móvil que se sumará a dicho crédito. El síndico afectará la suma recibida a los gastos que le demande el proceso de verificación y confección de los informes, con cargo de oportuna rendición de cuentas al juzgado quedando el remanente como suma a cuenta de honorarios a regularse por su actuación. Exclúyase del arancel a los créditos de causa laboral, y a los equivalentes a menos de tres (3) salarios mínimos vitales y móviles, sin necesidad de declaración judicial.`,
    `Es el trámite clave para cobrar: todo acreedor con deuda anterior al concurso debe pedirle al síndico que le "verifique" el crédito, por escrito, indicando monto, causa y privilegio, y acompañando los títulos. Ese pedido vale como una demanda (interrumpe la prescripción). Se paga un arancel del 10% de un salario mínimo, salvo los créditos laborales o los menores a 3 salarios mínimos, que están exentos.`),
  art('32 bis', 'Verificación por fiduciarios y otros sujetos legitimados',
    `Verificación por fiduciarios y otros sujetos legitimados. La verificación de los créditos puede ser solicitada por el fiduciario designado en emisiones de debentures, bonos convertibles, obligaciones negociables u otros títulos emitidos en serie; y por aquél a quien se haya investido de la legitimación o de poder de representación para actuar por una colectividad de acreedores. La extensión de las atribuciones del fiduciario, del legitimado o del representante se juzgará conforme a los contratos o documentos en función de los cuales haya sido investido de la calidad de fiduciario, legitimado o representante. No se exigirá ratificación ni presentación de otros poderes.`,
    `Cuando hay muchos acreedores que invirtieron en títulos emitidos en serie (obligaciones negociables, bonos, debentures), el fiduciario o representante de todos ellos puede pedir la verificación en nombre del conjunto, sin necesidad de que cada uno se presente ni de poderes adicionales.`),
  art('33', 'Facultades de información del síndico',
    `Facultades de información. El síndico debe realizar todas las compulsas necesarias en los libros y documentos del concursado y, en cuanto corresponda, en los del acreedor. Puede, asimismo, valerse de todos los elementos de juicio que estime útiles y, en caso de negativa a suministrarlos, solicitar del juez de la causa las medidas pertinentes. Debe conservar el legajo por acreedor presentado por el concursado, incorporando la solicitud de verificación y documentación acompañada por el acreedor, y formar y conservar los legajos correspondientes a los acreedores no denunciados que soliciten la verificación de sus créditos. En dichos legajos el síndico deberá dejar constancia de las medidas realizadas.`,
    `El síndico investiga: puede revisar los libros y papeles del deudor y de los acreedores, pedir todo lo que necesite y, si no se lo dan, recurrir al juez. Debe armar y conservar un legajo por cada acreedor con su pedido y la documentación.`),
  art('34', 'Período de observación de créditos',
    `Período de observación de créditos. Durante los DIEZ (10) días siguientes al vencimiento del plazo para solicitar la verificación, el deudor y los acreedores que lo hubieren hecho podrán concurrir al domicilio del síndico, a efectos de revisar los legajos y formular por escrito las impugnaciones y observaciones respecto de las solicitudes formuladas. Dichas impugnaciones deberán ser acompañadas de DOS (2) copias y se agregarán al legajo correspondiente, entregando el síndico al interesado constancia que acredite la recepción, indicando día y hora de la presentación. Dentro de las CUARENTA Y OCHO (48) horas de vencido el plazo previsto en el párrafo anterior, el síndico presentará al juzgado un juego de copias de las impugnaciones recibidas para su incorporación al legajo previsto en el artículo 279. Los trabajadores de la concursada que no tuvieren el carácter de acreedores tendrán derecho a revisar los legajos y ser informados por el síndico acerca de los créditos insinuados.`,
    `Tras cerrarse el plazo para pedir verificación, hay 10 días en los que el deudor y los acreedores pueden ir a la oficina del síndico, revisar los pedidos de los demás y observarlos o impugnarlos por escrito. También los trabajadores (aunque no sean acreedores) pueden revisar los legajos e informarse.`),
  art('35', 'Informe individual',
    `Informe individual. Vencido el plazo para la formulación de observaciones por parte del deudor y los acreedores, en el plazo de VEINTE (20) días, el síndico deberá redactar un informe sobre cada solicitud de verificación en particular, el que deberá ser presentado al juzgado. Se debe consignar el nombre completo de cada acreedor, su domicilio real y el constituido, monto y causa del crédito, privilegio y garantías invocados; además, debe reseñar la información obtenida, las observaciones que hubieran recibido las solicitudes, por parte del deudor y de los acreedores, y expresar respecto de cada crédito, opinión fundada sobre la procedencia de la verificación del crédito y el privilegio. También debe acompañar una copia, que se glosa al legajo a que se refiere el artículo 279, la cual debe quedar a disposición permanente de los interesados para su examen, y copia de los legajos.`,
    `El síndico presenta al juzgado un informe sobre cada acreedor: sus datos, el monto y causa del crédito, el privilegio invocado, las observaciones recibidas y su opinión fundada sobre si corresponde verificar el crédito. Es la base sobre la que el juez decide.`),
  art('36', 'Resolución judicial (verificado / admisible / inadmisible)',
    `Resolución judicial. Dentro de los DIEZ (10) días de presentado el informe por parte del síndico, el juez decidirá sobre la procedencia y alcances de las solicitudes formuladas por los acreedores. El crédito o privilegio no observados por el síndico, el deudor o los acreedores es declarado verificado, si el juez lo estima procedente. Cuando existan observaciones, el juez debe decidir declarando admisible o inadmisible el crédito o el privilegio. Estas resoluciones son definitivas a los fines del cómputo en la evaluación de mayorías y base del acuerdo, sin perjuicio de lo dispuesto en el artículo siguiente.`,
    `El juez resuelve sobre cada crédito en 3 categorías: "verificado" (sin observaciones, queda firme), "admisible" (con observaciones pero aceptado, sujeto a revisión) o "inadmisible" (rechazado, también revisable). Esta resolución define quiénes votan y con qué monto el acuerdo preventivo.`),
  art('37', 'Efectos de la resolución',
    `Efectos de la resolución. La resolución que declara verificado el crédito y, en su caso, el privilegio, produce los efectos de la cosa juzgada, salvo dolo. La que lo declara admisible o inadmisible puede ser revisada a petición del interesado, formulada dentro de los VEINTE (20) días siguientes a la fecha de la resolución prevista en el artículo 36. Vencido este plazo, sin haber sido cuestionada, queda firme y produce también los efectos de la cosa juzgada, salvo dolo.`,
    `El crédito "verificado" tiene fuerza de cosa juzgada (no se discute más, salvo que hubo dolo). El "admisible" o "inadmisible" se puede revisar dentro de los 20 días con un incidente de revisión; si nadie lo cuestiona, también queda firme.`),
  art('38', 'Invocación de dolo. Efectos',
    `Invocación de dolo. Efectos. Las acciones por dolo a que se refiere el artículo precedente tramitan por vía ordinaria ante el juzgado del concurso, y caducan a los NOVENTA (90) días de la fecha en que se dictó la resolución judicial prevista en el artículo 36. La deducción de esta acción no impide el derecho del acreedor a obtener el cumplimiento del acuerdo, sin perjuicio de las medidas precautorias que puedan dictarse.`,
    `Si un crédito se verificó por fraude (dolo), se puede atacar con una acción ordinaria ante el juez del concurso, pero hay solo 90 días para iniciarla. Mientras tanto, el acreedor afectado igual conserva su derecho a que se cumpla el acuerdo.`),

  // SECCIÓN IV — Informe general del síndico
  art('39', 'Informe general: oportunidad y contenido',
    `Oportunidad y contenido. Treinta (30) días después de presentado el informe individual de los créditos, el síndico debe presentar un informe general, el que contiene: 1) El análisis de las causas del desequilibrio económico del deudor. 2) La composición actualizada y detallada del activo, con la estimación de los valores probables de realización de cada rubro, incluyendo intangibles. 3) La composición del pasivo, que incluye también, como previsión, detalle de los créditos que el deudor denunciara en su presentación y que no se hubieren presentado a verificar, así como los demás que resulten de la contabilidad o de otros elementos de juicio verosímiles. 4) Enumeración de los libros de contabilidad, con dictamen sobre la regularidad, las deficiencias que se hubieran observado, y el cumplimiento de los artículos 43, 44 y 51 del Código de Comercio. 5) La referencia sobre las inscripciones del deudor en los registros correspondientes y, en caso de sociedades, sobre las del contrato social y sus modificaciones, indicando el nombre y domicilio de los administradores y socios con responsabilidad ilimitada. 6) La expresión de la época en que se produjo la cesación de pagos, hechos y circunstancias que fundamenten el dictamen. 7) En caso de sociedades, debe informar si los socios realizaron regularmente sus aportes, y si existe responsabilidad patrimonial que se les pueda imputar por su actuación en tal carácter. 8) La enumeración concreta de los actos que se consideren susceptibles de ser revocados, según lo disponen los artículos 118 y 119. 9) Opinión fundada respecto del agrupamiento y clasificación que el deudor hubiere efectuado respecto de los acreedores. 10) Deberá informar, si el deudor resulta pasible del trámite legal prevenido por el Capítulo III de la ley 25.156, por encontrarse comprendido en el artículo 8° de dicha norma.`,
    `30 días después del informe individual, el síndico presenta el "informe general": el panorama completo del deudor. Analiza por qué entró en crisis, detalla el activo (con su valor real de venta) y el pasivo, evalúa los libros contables, fija la fecha de la cesación de pagos, señala los actos que podrían revocarse y opina sobre cómo el deudor clasificó a los acreedores. Es el documento central para entender la situación.`),
  art('40', 'Observaciones al informe general',
    `Observaciones al informe. Dentro de los DIEZ (10) días de presentado el informe previsto en el artículo anterior, el deudor y quienes hayan solicitado verificación pueden presentar observaciones al informe; son agregadas sin sustanciación y quedan a disposición de los interesados para su consulta.`,
    `El deudor y los acreedores tienen 10 días para observar el informe general del síndico. Esas observaciones se agregan al expediente y quedan disponibles para consulta, sin abrir un trámite especial.`),
];

// Explicaciones en lenguaje claro para los artículos tomados del texto generado
// (art. 41 en adelante). Se completan por tandas — el texto oficial ya está.
const EXPLICACIONES: Record<string, string> = {
  // CAPÍTULO IV — Propuesta, período de exclusividad y acuerdo (arts. 41-48 bis)
  '41': 'El deudor agrupa a sus acreedores en categorías (como mínimo: quirografarios, quirografarios laborales y privilegiados) para poder ofrecerles propuestas de acuerdo diferenciadas.',
  '42': 'El juez fija de forma definitiva las categorías y los acreedores de cada una, y arma el comité de control con un acreedor por categoría más representantes de los trabajadores.',
  '43': 'El "período de exclusividad": el deudor tiene 90 días (prorrogables) para negociar y juntar las conformidades. Las propuestas pueden ser quita, espera, entrega de bienes, capitalización de la deuda, etc., e iguales dentro de cada categoría. Si no hace pública su propuesta a tiempo, va a la quiebra.',
  '44': 'El deudor también puede ofrecer una propuesta a los acreedores privilegiados; requiere las mayorías del art. 46 y la unanimidad de los privilegiados especiales alcanzados.',
  '45': 'Las mayorías para aprobar el acuerdo: mayoría absoluta de acreedores que represente las dos terceras partes del capital, en cada categoría. Se excluye del cómputo a parientes y controlantes del deudor. Antes del vencimiento hay una audiencia informativa.',
  '45 bis': 'Cuando hay acreedores por títulos emitidos en serie (obligaciones negociables, bonos), votan reunidos en asamblea y su conformidad se computa por el capital que adhirió, a través del fiduciario.',
  '46': 'Si el deudor no presenta en plazo las conformidades necesarias, se lo declara en quiebra (salvo que aplique el salvataje del art. 48).',
  '47': 'Si el deudor ofreció acuerdo a los privilegiados y no obtuvo sus mayorías, solo va a quiebra si en el expediente había condicionado la propuesta a los quirografarios a la aprobación de la de privilegiados.',
  '48': 'El "cramdown" o salvataje: para ciertas sociedades, si el deudor no logra el acuerdo no se declara la quiebra de inmediato. Se abre un registro para que acreedores, la cooperativa de trabajo o terceros compitan por comprar la empresa y proponer su propio acuerdo a los acreedores.',
  '48 bis': 'Si en el salvataje se inscribe la cooperativa formada por los trabajadores, sus créditos laborales (indemnizaciones) se calculan y pueden convertirse en cuotas de capital de la cooperativa, con exención de ciertos depósitos para facilitarlo.',
  // CAPÍTULO V — Impugnación, homologación, cumplimiento y nulidad (arts. 49-64)
  '49': 'Dentro de los 3 días de presentadas las conformidades, el juez dicta una resolución haciendo saber que existe acuerdo preventivo.',
  '50': 'Los acreedores con derecho a voto pueden impugnar el acuerdo dentro de 5 días, pero solo por causales tasadas: error en el cómputo de las mayorías, falta de representación, exageración fraudulenta del pasivo, ocultación del activo o vicios de forma.',
  '51': 'Tramitada la impugnación: si el juez la considera procedente, declara la quiebra (o aplica el salvataje); si la considera improcedente, homologa el acuerdo. Ambas decisiones son apelables.',
  '52': 'La homologación: sin impugnaciones (o rechazadas), el juez aprueba el acuerdo. Puede incluso imponerlo a categorías que no lo aceptaron (cramdown power) si se cumplen ciertos requisitos. Nunca homologa una propuesta abusiva o en fraude a la ley.',
  '53': 'La resolución que homologa el acuerdo dispone las medidas judiciales para cumplirlo (reorganización de la sociedad, transferencia de acciones en el salvataje, etc.).',
  '54': 'Los honorarios a cargo del deudor se pueden exigir a los 90 días de la homologación (o con la primera cuota que venza antes). Si no se pagan, se puede pedir la quiebra.',
  '55': 'El acuerdo homologado "nova" (reemplaza por nuevas) todas las deudas anteriores al concurso. Pero esa novación no libera a los fiadores ni a los codeudores solidarios, que siguen obligados.',
  '56': 'El acuerdo homologado obliga a TODOS los acreedores quirografarios anteriores, hayan participado o no. Regula además la verificación tardía: el acreedor que no se presentó a tiempo puede hacerlo por incidente, dentro de los 2 años de la presentación.',
  '57': 'Las cláusulas para acreedores privilegiados solo producen efecto si el acuerdo se homologa. Los privilegiados no incluidos pueden ejecutar su crédito por separado o pedir la quiebra del deudor.',
  '58': 'El reclamo contra un crédito admitido no frena el cumplimiento del acuerdo: el concursado debe poner a disposición del juzgado la prestación que le correspondería a ese acreedor.',
  '59': 'Homologado el acuerdo y cumplidas las medidas, el juez declara concluido el concurso y cesa el síndico. Tras la declaración de cumplimiento, el deudor no puede pedir otro concurso preventivo por 1 año.',
  '60': 'Cualquier acreedor comprendido en el acuerdo puede pedir su nulidad dentro de un plazo de caducidad de 6 meses, y solo por dolo: pasivo exagerado, privilegios falsos o activo ocultado.',
  '61': 'La sentencia que declara la nulidad del acuerdo debe a la vez declarar la quiebra del deudor y disponer las medidas de la quiebra.',
  '62': 'Otros efectos de la nulidad: libera al fiador, los acreedores recuperan los derechos y privilegios que tenían antes del concurso, se abre un nuevo período de información y los bienes se liquidan sin más trámite.',
  '63': 'Si el deudor no cumple el acuerdo (total o parcialmente, incluidas las garantías), el juez declara la quiebra a pedido de un acreedor o controlador, o de oficio si el deudor manifiesta que no podrá cumplir.',
  '64': 'Si se declara la quiebra con un acuerdo preventivo pendiente de cumplimiento, se abre el período informativo y se liquidan los bienes; entiende el mismo juez y actúa el mismo síndico del concurso.',
  // CAPÍTULO VI — Concurso en caso de agrupamiento (arts. 65-68)
  '65': 'Dos o más personas (humanas o jurídicas) que integran de forma permanente un mismo grupo económico pueden pedir su concurso preventivo en conjunto, probando la existencia del agrupamiento.',
  '66': 'Para abrir el concurso del grupo alcanza con que uno solo de sus integrantes esté en cesación de pagos, siempre que ese estado pueda afectar a los demás integrantes.',
  '67': 'Entiende el juez del integrante con el activo más importante. La sindicatura es única, hay un proceso por cada concursado y un informe general único con el activo y pasivo consolidados. Las propuestas pueden tratarse unificadamente (con mayorías especiales) o individualmente.',
  '68': 'Quien garantizó las obligaciones de un concursado puede pedir su propio concurso preventivo para que tramite junto con el de su garantizado, dentro de los 30 días de la última publicación de edictos.',
  // CAPÍTULO VII — Acuerdo preventivo extrajudicial (arts. 69-76)
  '69': 'El Acuerdo Preventivo Extrajudicial (APE): el deudor en cesación de pagos o en dificultades económicas generales puede acordar privadamente con sus acreedores y luego someter ese acuerdo a homologación judicial.',
  '70': 'El acuerdo extrajudicial puede otorgarse en instrumento privado, con las firmas de las partes certificadas por escribano público; no hace falta que todos firmen el mismo día.',
  '71': 'Las partes pueden darle al acuerdo extrajudicial el contenido que quieran, y las obliga entre ellas aun cuando no se homologue judicialmente, salvo que hayan pactado lo contrario.',
  '72': 'Para homologar el acuerdo extrajudicial hay que presentar al juez, certificados por contador, el estado de activo y pasivo, el listado de acreedores y de juicios, los libros y el capital que firmó. Publicados los edictos, se suspenden las acciones patrimoniales contra el deudor.',
  '73': 'Para homologar el acuerdo extrajudicial se necesita la conformidad de la mayoría absoluta de acreedores quirografarios que representen las dos terceras partes del pasivo quirografario total.',
  '74': 'La presentación del acuerdo extrajudicial para homologar se publica por edictos durante 5 días, para que los acreedores se enteren y puedan oponerse.',
  '75': 'Los acreedores pueden oponerse al acuerdo extrajudicial dentro de 10 días, solo por omisiones o exageraciones del activo o pasivo, o por falta de la mayoría exigida. Sin oposiciones y cumplidos los requisitos, el juez lo homologa.',
  '76': 'El acuerdo extrajudicial homologado produce los mismos efectos que el acuerdo preventivo (obliga a todos los quirografarios anteriores, art. 56) y queda sometido a las reglas de cumplimiento, nulidad e incumplimiento.',

  // ─── TÍTULO III — QUIEBRA ───────────────────────────────────────────────────
  // CAPÍTULO I — Declaración (arts. 77-101)
  '77': 'La quiebra se declara en tres situaciones: cuando fracasa el concurso preventivo (arts. 46, 47, 48, 51, 54, 61 y 63), a pedido de un acreedor, o a pedido del propio deudor.',
  '78': 'El estado de cesación de pagos se prueba por cualquier hecho que muestre que el deudor no puede cumplir regularmente sus obligaciones. No hace falta que haya varios acreedores: alcanza con uno.',
  '79': 'Enumera los "hechos reveladores" de la cesación de pagos: que el deudor lo reconozca, la mora, su fuga u ocultación, el cierre del establecimiento, vender a precio vil, el fraude a los acreedores o cualquier medio ruinoso para conseguir fondos.',
  '80': 'Cualquier acreedor con crédito exigible puede pedir la quiebra. Si tiene privilegio especial, debe probar sumariamente que el bien afectado no alcanza para cubrirlo, salvo que sea un crédito laboral (exento de esa prueba).',
  '81': 'No pueden pedir la quiebra del deudor su cónyuge, sus ascendientes o descendientes, ni quienes le hayan comprado (cesionarios) sus créditos.',
  '82': 'El pedido del propio deudor de su quiebra prevalece sobre el de los acreedores, en cualquier estado del trámite, mientras la quiebra no haya sido declarada.',
  '83': 'Si la quiebra la pide un acreedor, este debe probar sumariamente su crédito, los hechos reveladores de la cesación de pagos y que el deudor es un sujeto que puede quebrar (art. 2).',
  '84': 'Probados esos extremos, el juez emplaza al deudor para que en 5 días invoque y pruebe lo que estime. Luego resuelve admitiendo o rechazando la quiebra: no existe un "juicio de antequiebra" largo.',
  '85': 'Antes de declarar la quiebra, el juez puede dictar medidas precautorias para proteger el patrimonio del deudor (inhibición general, intervención de sus negocios) si hay verosimilitud del reclamo y peligro en la demora.',
  '86': 'Si la quiebra la pide el deudor, debe acompañar varios requisitos del art. 11 (aunque su omisión no impide declararla) y poner todos sus bienes a disposición del juzgado para que los funcionarios tomen posesión.',
  '87': 'El acreedor que pidió la quiebra puede desistir mientras no se haya citado al deudor (art. 84). El deudor que pidió su propia quiebra no puede desistir, salvo que pruebe —antes de los edictos— que ya superó la cesación de pagos.',
  '88': 'Detalla todo lo que debe disponer la sentencia de quiebra: individualizar al fallido, inhibirlo, ordenar la entrega de los bienes y libros al síndico, prohibir los pagos al fallido, interceptar su correspondencia, ordenar la realización de los bienes y el sorteo del síndico, y fijar la fecha de verificación.',
  '89': 'Dentro de las 24 horas de dictada la sentencia se publican edictos por 5 días dando a conocer la quiebra y los datos del síndico, sin necesidad de pago previo.',
  '90': 'El fallido que reúne las condiciones para concursarse puede pedir "convertir" la quiebra en concurso preventivo, dentro de los 10 días de la última publicación de edictos. No puede hacerlo quien quebró por incumplir un acuerdo o estando en período de inhibición.',
  '91': 'Si el deudor pide la conversión, ya no puede impugnar la sentencia de quiebra por reposición; si ya la había interpuesto, se la tiene por desistida.',
  '92': 'Para la conversión, el deudor debe cumplir los requisitos del art. 11 (los mismos del concurso preventivo) al hacer el pedido o en el plazo que el juez le fije.',
  '93': 'Cumplidos los requisitos, el juez deja sin efecto la sentencia de quiebra y abre el concurso preventivo. Solo puede rechazar la conversión si no se cumplieron los requisitos del art. 11.',
  '94': 'El fallido puede pedir la "reposición" (revocación) de la quiebra cuando fue declarada a pedido de un acreedor, dentro de los 5 días de conocida la sentencia o de la última publicación de edictos.',
  '95': 'La reposición solo puede fundarse en que no existían los presupuestos para la quiebra: que el deudor no era sujeto concursable o que no estaba realmente en cesación de pagos.',
  '96': 'El juez puede revocar la quiebra sin abrir incidente ("levantamiento sin trámite") si el fallido deposita en pago los créditos que acreditaron la cesación de pagos, sus accesorios y los gastos.',
  '97': 'Interponer el recurso no frena el proceso de quiebra, salvo en lo que implique disposición (venta) de bienes.',
  '98': 'Si se revoca la quiebra, cesan sus efectos. Pero los actos que el síndico ya hizo legalmente y la resolución de los contratos en curso siguen siendo válidos y oponibles al deudor.',
  '99': 'Revocada la quiebra, quien la pidió con dolo o culpa grave responde por los daños y perjuicios causados al deudor. Esa acción tramita ante el mismo juez del concurso.',
  '100': 'El deudor o cualquier acreedor (menos el que pidió la quiebra) pueden plantear que el juzgado es incompetente, en el mismo plazo que la reposición.',
  '101': 'El planteo de incompetencia no suspende el trámite si el deudor está inscripto en el Registro Público de la jurisdicción, y nunca frena los efectos de la quiebra. Admitida, el expediente pasa al juez competente y valen las actuaciones ya cumplidas.',
  // CAPÍTULO II — Efectos de la quiebra (arts. 102-159)
  '102': 'El fallido (y los administradores de la sociedad) deben colaborar con el juez y el síndico para esclarecer su situación patrimonial, y comparecer cada vez que se los cite, incluso por la fuerza pública si no asisten.',
  '103': 'Hasta que se presente el informe general, el fallido y sus administradores no pueden salir del país sin autorización judicial. El juez puede extender esa prohibición de salida hasta 6 meses por resolución fundada.',
  '104': 'El fallido conserva el derecho a trabajar: tareas artesanales, su profesión o en relación de dependencia. Las deudas que contraiga antes de rehabilitarse pueden dar lugar a un nuevo concurso sobre los bienes que queden.',
  '105': 'La muerte, incapacidad o inhabilitación del fallido no afectan el trámite ni los efectos de la quiebra: sus herederos o su representante lo sustituyen en el proceso.',
  '106': 'La sentencia de quiebra aplica de inmediato las medidas de desapoderamiento de esta sección.',
  '107': 'El "desapoderamiento": el fallido pierde de pleno derecho la administración y disposición de sus bienes (los que tiene al declararse la quiebra y los que adquiera hasta su rehabilitación). Es el efecto central de la quiebra.',
  '108': 'Enumera los bienes que NO caen en el desapoderamiento: los derechos no patrimoniales, los bienes inembargables, el usufructo sobre los bienes de los hijos menores, la administración de los bienes del cónyuge, las indemnizaciones por daños a su persona, y los excluidos por otras leyes.',
  '109': 'El síndico administra los bienes y participa de su disposición. Los actos que el fallido realice sobre los bienes desapoderados, y los pagos que haga o reciba, son ineficaces.',
  '110': 'El fallido pierde la legitimación para actuar en los juicios sobre los bienes desapoderados (actúa el síndico). Sí puede pedir medidas conservatorias urgentes, observar créditos que pretenden verificarse e intervenir en los incidentes.',
  '111': 'El fallido puede aceptar o repudiar herencias y legados. Si acepta, los acreedores del causante solo cobran sobre esos bienes después de pagados los del fallido y los gastos del concurso.',
  '112': 'Es ineficaz frente a los acreedores la condición de que un bien legado o donado no quede comprendido en el desapoderamiento (aunque la donación o legado en sí subsistan).',
  '113': 'Los bienes donados al fallido después de la quiebra y hasta su rehabilitación ingresan al concurso y quedan desapoderados. Si la donación tiene un cargo, el síndico puede rechazarla con autorización judicial.',
  '114': 'La correspondencia dirigida al fallido se entrega al síndico, que la abre ante el fallido (o el juez), devolviéndole la que sea estrictamente personal.',
  '115': 'La fecha que se fije como inicio de la cesación de pagos hace cosa juzgada respecto de quienes intervinieron en su determinación, y es presunción (con prueba en contra) para los terceros que no intervinieron.',
  '116': 'La fecha de inicio de la cesación de pagos no puede retrotraerse más de 2 años antes del auto de quiebra. El "período de sospecha" es el lapso entre esa fecha y la sentencia de quiebra: en él se controlan los actos del deudor.',
  '117': 'Dentro de los 30 días del informe general, los interesados pueden observar la fecha de inicio de la cesación de pagos que propuso el síndico. La resolución que la fija es apelable.',
  '118': 'Son ineficaces de pleno derecho (sin necesidad de juicio) los actos del deudor en el período de sospecha que sean: a título gratuito, pago anticipado de deudas no vencidas, o nuevas hipotecas/prendas por obligaciones que no las tenían.',
  '119': 'Otros actos perjudiciales del período de sospecha pueden declararse ineficaces si el tercero conocía la cesación de pagos del deudor. La acción la ejerce el síndico (con autorización de los acreedores) y perime a los 6 meses.',
  '120': 'Si el síndico no inicia la acción, cualquier acreedor puede deducirla a su costa tras intimarlo 30 días. También puede ejercer la acción revocatoria ordinaria. Si gana, tiene derecho a sus gastos y a una preferencia sobre los bienes recuperados.',
  '121': 'No se anulan los actos de administración ordinaria, ni los que excedan el giro o de disposición autorizados judicialmente, realizados durante un concurso preventivo previo o el cumplimiento del acuerdo.',
  '122': 'Si el acreedor que pidió la quiebra recibe un pago de un tercero para su crédito, se presume hecho a favor de todos los acreedores: debe reintegrar al concurso lo recibido.',
  '123': 'Si se declara inoponible una hipoteca o prenda, los acreedores de rango posterior no se benefician con ese lugar: las sumas que le hubieran correspondido al acto inoponible ingresan al concurso.',
  '124': 'Las acciones de ineficacia (arts. 118-120) caducan a los 3 años de la sentencia de quiebra. Los bienes que se recuperen por estas acciones quedan sujetos al desapoderamiento.',
  '125': 'Declarada la quiebra, todos los acreedores quedan sometidos a esta ley y solo pueden ejercer sus derechos sobre los bienes en la forma que ella prevé (proceso colectivo).',
  '126': 'Todos los acreedores deben verificar sus créditos. Los que tienen hipoteca, prenda o warrant pueden además reclamar el pago ejecutando la cosa garantizada en cualquier momento (concurso especial), comprobando sus títulos.',
  '127': 'Los créditos no dinerarios, en moneda extranjera o calculados sobre otros bienes, concurren a la quiebra por su valor en pesos a la fecha de la declaración (o del vencimiento, a opción del acreedor).',
  '128': 'Con la sentencia de quiebra, todas las obligaciones del fallido que estaban a plazo se consideran vencidas de pleno derecho (vencen anticipadamente).',
  '129': 'La quiebra suspende el curso de todos los intereses. Excepciones: los intereses compensatorios de créditos con garantía real (hasta lo que produzca el bien gravado) y los de los créditos laborales, que sí se siguen devengando.',
  '130': 'La compensación de deudas recíprocas entre el fallido y un acreedor solo vale si se produjo antes de la declaración de la quiebra; después, ya no.',
  '131': 'La quiebra suspende el derecho de retención sobre bienes desapoderables: el que retenía debe entregarlos al síndico, conservando el privilegio del art. 241 inc. 5. Si la quiebra cesa antes de venderse el bien, recupera la retención.',
  '132': 'El "fuero de atracción": la quiebra atrae al juzgado todas las acciones patrimoniales contra el fallido, salvo las ejecuciones de garantías reales y las excepciones del art. 21. Los juicios atraídos se suspenden cuando la sentencia de quiebra queda firme.',
  '133': 'Si el fallido es codemandado junto con otros, el actor puede seguir el juicio en el tribunal original desistiendo contra el fallido (y verificar su crédito aparte), o, si hay litisconsorcio necesario, continuar con intervención del síndico.',
  '134': 'La quiebra deja sin efecto las cláusulas de arbitraje pactadas con el deudor, salvo que el tribunal de árbitros ya se hubiera constituido antes de la sentencia. El juez puede autorizar al síndico a pactar arbitraje en casos puntuales.',
  '135': 'El acreedor de varios obligados solidarios puede presentarse en la quiebra de cada uno por el valor total de su crédito, hasta cobrarlo íntegramente. El coobligado o garante no fallido que paga se subroga en los derechos del acreedor.',
  '136': 'No hay acción entre los concursos de los coobligados solidarios por los dividendos pagados al acreedor, salvo que el total pagado supere el crédito, en cuyo caso el acreedor debe restituir el excedente.',
  '137': 'El coobligado o fiador del fallido garantizado con prenda o hipoteca sobre bienes de éste concurre a la quiebra para asegurar su derecho de repetir; primero cobra el acreedor y luego el que ejerce la repetición.',
  '138': 'Los terceros pueden pedir la restitución de los bienes que están en poder del fallido entregados por un título que no transmitía la propiedad (depósito, locación, etc.), acreditando su derecho.',
  '139': 'El que envió bienes al fallido para transferirle la propiedad puede recuperar la posesión si: el fallido no tomó posesión efectiva antes de la quiebra, no cumplió íntegramente su prestación, y un tercero no adquirió derechos reales sobre ellos.',
  '140': 'Regula cómo ejerce ese derecho el remitente: debe pedirlo dentro de 30 días de los edictos; el síndico puede optar por cumplir la contraprestación y quedarse el bien; y el enajenante debe pagar los gastos y depositar lo recibido.',
  '141': 'Si un tercero adquirió un derecho real sobre los bienes y debe la contraprestación, el enajenante puede pedir la cesión de ese crédito (si es de igual naturaleza) o tener un privilegio especial sobre lo pendiente. Igual derecho sobre las indemnizaciones del seguro.',
  '142': 'El síndico está legitimado para ejercer todos los derechos patrimoniales que el deudor tenía antes de la quiebra. Son nulos los pactos que se lo impidan. La quiebra no genera derecho de los terceros a indemnización por aplicar esta ley.',
  '143': 'Contratos en curso al declararse la quiebra: si el fallido ya cumplió su parte, el otro debe cumplir; si el tercero ya cumplió, debe verificar su crédito; si ambas prestaciones están pendientes, el tercero puede pedir la resolución del contrato.',
  '144': 'Procedimiento del contrato con prestaciones pendientes: el tercero tiene 20 días para avisar si quiere continuarlo o resolverlo; el síndico opina en su informe; y el juez decide al resolver sobre la continuación de la empresa. Pasados 60 días sin decisión, el tercero puede forzarla.',
  '145': 'La quiebra deja sin efecto las cláusulas (legales o del contrato) que permiten resolverlo por incumplimiento, cuando esa resolución no se había producido o demandado judicialmente antes de la sentencia de quiebra.',
  '146': 'Las promesas de contrato o los contratos sin la forma legal no son exigibles al concurso, salvo continuación autorizada. Importante: los boletos de compraventa de inmuebles a comprador de buena fe que pagó al menos el 25% del precio son oponibles a la quiebra, y el juez ordena escriturar.',
  '147': 'Quedan resueltos por la quiebra los contratos cuya prestación del fallido sea personal e irreemplazable, los de ejecución continuada y los normativos. Incluye el mandato, la cuenta corriente, la agencia y la concesión o distribución.',
  '148': 'En el contrato de comisión de compraventa: si el fallido vendió por un comitente, este puede reclamar el precio directamente al comprador; si compró por el comitente, el vendedor puede cobrar directamente al comitente. Siempre con vista al síndico y autorización del juez.',
  '149': 'Si un socio ejerció el derecho de receso (retirarse y cobrar su parte) estando la sociedad ya en cesación de pagos, debe reintegrar al concurso todo lo que percibió por ese motivo.',
  '150': 'La quiebra de la sociedad hace exigibles de inmediato los aportes que los socios no habían integrado, hasta cubrir el interés de los acreedores y los gastos del concurso.',
  '151': 'La quiebra del socio gestor disuelve la sociedad accidental o en participación. Los demás socios solo tienen derecho sobre los bienes después de pagados todos los acreedores y gastos.',
  '152': 'Si la fallida emitió debentures u obligaciones negociables impagos: con garantía especial se aplican las reglas de los acreedores hipotecarios/prendarios; con garantía flotante o común, el fiduciario actúa como liquidador junto al síndico.',
  '153': 'En un contrato a término, la quiebra de una parte da a la otra derecho a verificar la diferencia a su favor a la fecha de la sentencia. Si no hay diferencias en ese momento, el contrato se resuelve sin deberse nada.',
  '154': 'La quiebra del asegurado NO resuelve el seguro de daños patrimoniales (es nulo el pacto en contrario). Si el contrato continúa, el asegurador es acreedor del concurso por toda la prima impaga.',
  '155': 'Cuando la quiebra exime de protestar los títulos, el cese posterior del concurso no altera esa dispensa. La restitución de lo pagado por esos documentos produce los efectos del protesto para accionar contra los demás obligados.',
  '156': 'En el concurso solo se puede reclamar el crédito por alimentos que el fallido adeudaba antes de la sentencia de quiebra (no los posteriores).',
  '157': 'Locación de inmuebles: si el fallido es locador, la locación continúa normalmente; si es locatario para explotación comercial, rigen los arts. 144 o 197; si la usa solo como vivienda, el contrato es ajeno al concurso.',
  '158': 'La quiebra del deudor de una renta vitalicia onerosa la resuelve, y el acreedor debe verificar su crédito por lo adeudado. Si la renta era gratuita, el contrato se resuelve sin más obligación para el concurso.',
  '159': 'Para las relaciones patrimoniales no previstas expresamente, el juez decide por analogía con las normas similares, atendiendo a la protección del crédito, la integridad del patrimonio y de la empresa, y el interés general.',
  // CAPÍTULO III — Extensión de la quiebra. Grupos económicos. Responsabilidad de terceros (arts. 160-176)
  '160': 'La quiebra de una sociedad arrastra automáticamente la quiebra de sus socios con responsabilidad ilimitada (incluso los que se retiraron o fueron excluidos después de la cesación de pagos, por las deudas existentes a esa fecha).',
  '161': 'La quiebra se "extiende" (alcanza el patrimonio) de: quien usó a la fallida como pantalla y dispuso de sus bienes como propios en fraude a los acreedores; la persona controlante que desvió el interés de la sociedad en beneficio del grupo; y quien tiene una confusión patrimonial inescindible con la fallida.',
  '162': 'El juez de la quiebra es competente para decidir su extensión. Declarada la extensión, entiende en todos los concursos el juez del que tenga el activo más importante.',
  '163': 'La extensión puede pedirla el síndico o cualquier acreedor, en cualquier momento después de la quiebra y hasta 6 meses después del informe general (plazo que se extiende si hubo acuerdo rechazado, no homologado o nulo).',
  '164': 'El pedido de extensión tramita como juicio ordinario, con participación del síndico y de todas las personas a las que se quiere extender la quiebra. La instancia caduca a los 6 meses. El juez puede dictar medidas precautorias sobre los imputados.',
  '165': 'Los recursos contra la sentencia de quiebra no frenan el trámite de extensión, pero la sentencia que la declara solo puede dictarse una vez desestimados esos recursos.',
  '166': 'Al decretar la extensión, el juez coordina los procedimientos de todas las quiebras, y el síndico ya designado interviene en los concursos de todas las personas alcanzadas.',
  '167': 'Si la extensión se funda en confusión patrimonial inescindible (art. 161 inc. 3), se forma una "masa única": los patrimonios se tratan como uno solo. El crédito a cargo de varios fallidos concurre una sola vez por el importe mayor.',
  '168': 'En los demás casos hay "masas separadas": los bienes y créditos de cada fallido se consideran por separado. Los sobrantes de cada masa forman un fondo común para los acreedores no satisfechos, sin atender a privilegios (no participan los controlantes fraudulentos).',
  '169': 'Con masa única hay una sola fecha de inicio de la cesación de pagos para todos los fallidos; con masas separadas, una fecha por cada fallido.',
  '170': 'Los créditos entre los fallidos se verifican por informe del síndico (sin necesidad de pedido de verificación) y no participan del fondo común; en la masa única directamente no se consideran.',
  '171': 'Los efectos de la quiebra declarada por extensión se producen recién a partir de la sentencia que la decreta (no se retrotraen a la quiebra original).',
  '172': 'Si dos o más personas forman un grupo económico (incluso con relaciones de control) pero sin las conductas fraudulentas del art. 161, la quiebra de una de ellas NO se extiende a las demás. El solo hecho de ser grupo no contagia la quiebra.',
  '173': 'Los administradores, representantes o gestores del fallido que con dolo produjeron o agravaron la insolvencia deben indemnizar los daños. Los terceros que participaron dolosamente en disminuir el activo o exagerar el pasivo deben reintegrar los bienes e indemnizar, y pierden todo derecho en el concurso.',
  '174': 'Esa responsabilidad alcanza los actos realizados hasta 1 año antes del inicio de la cesación de pagos. La acción la deduce el síndico por juicio ordinario, prescribe a los 2 años de la sentencia de quiebra y la instancia caduca a los 6 meses.',
  '175': 'Las acciones de responsabilidad contra socios limitadamente responsables, administradores, síndicos y liquidadores las ejerce el síndico. Las acciones ya iniciadas continúan ante el juzgado del concurso.',
  '176': 'El juez puede dictar medidas precautorias por el monto que fije, incluso antes de iniciar la acción, siempre que se acredite sumaria y verosímilmente la responsabilidad imputada. Estas acciones tramitan ante el juez del concurso.',
  // CAPÍTULO IV — Incautación, conservación y administración de los bienes (arts. 177-199)
  '177': 'Dictada la quiebra se "incautan" de inmediato los bienes y papeles del fallido: puede ser por clausura del establecimiento, entrega de los bienes al síndico con inventario, o dejándolos en poder de terceros depositarios. Los bienes imprescindibles para la subsistencia del fallido y su familia se le entregan a él.',
  '178': 'Si el síndico todavía no aceptó el cargo, las diligencias de incautación se hacen igual y se ordena la vigilancia policial necesaria para custodiar los bienes.',
  '179': 'El síndico debe conservar y administrar los bienes a su cargo, tomando posesión de ellos bajo inventario (puede hacerlo mediante un tercero que lo represente).',
  '180': 'El síndico se incauta de los libros de comercio y papeles del deudor, cerrando los espacios en blanco y dejando una nota firmada sobre las hojas escritas, para evitar manipulaciones.',
  '181': 'Si los bienes están en lugares que no ofrecen seguridad, el síndico debe pedir y practicar directamente las medidas más urgentes para evitar sustracciones, pérdidas o deterioros, avisando enseguida al juez.',
  '182': 'El síndico debe cobrar los créditos a favor del fallido e iniciar los juicios necesarios. No necesita autorización para eso, pero sí para transigir, dar quitas o esperas, novar o ir a arbitraje. Puede litigar sin pagar tasa de justicia por adelantado.',
  '183': 'El dinero que se recaude se deposita a la orden del juez dentro de 3 días. Ciertos créditos prioritarios (gastos de conservación y laborales de pronto pago) se pagan de inmediato. El juez puede autorizar al síndico a conservar fondos para gastos o a colocarlos a interés.',
  '184': 'El síndico debe pedir la venta inmediata de los bienes perecederos, los que pierden valor rápidamente y los de conservación costosa, en cualquier momento del proceso. También de los necesarios para afrontar los gastos del juicio.',
  '185': 'El síndico puede celebrar los contratos necesarios (incluso seguros) para conservar y administrar los bienes, con autorización judicial; si es urgente, puede contratar directamente avisando enseguida al juez.',
  '186': 'Para que los bienes den frutos, el síndico puede alquilarlos o hacer contratos sobre ellos (sin disponer de los bienes ni exceder ciertos plazos), siempre con autorización previa del juez.',
  '187': 'El juez puede pedir que se presenten varias propuestas de contrato y que se ofrezcan garantías. La cooperativa de trabajadores del establecimiento puede proponer contrato, garantizándolo con los créditos laborales que sus asociados afecten voluntariamente.',
  '188': 'Después de la quiebra y antes de venderse el bien, los terceros pueden pedir la restitución del art. 138, con vista al síndico (y al fallido si tiene reposición en trámite). El juez puede exigir una caución si aún no terminó la verificación.',
  '189': 'El síndico puede continuar de inmediato la explotación si interrumpirla causaría un daño grave a los acreedores o al patrimonio, o para conservar la fuente de trabajo si 2/3 del personal o de los acreedores laborales, organizados en cooperativa, lo solicitan. Reglas especiales para empresas de servicios públicos.',
  '190': 'En toda quiebra, el síndico debe informar al juez (en 20 días desde que acepta el cargo) si conviene continuar la explotación o vender la empresa en marcha. Los trabajadores que representen 2/3 del personal pueden pedir continuar como cooperativa, presentando un proyecto de explotación.',
  '191': 'El juez autoriza la continuación de la empresa si interrumpirla bajaría su valor de realización, para concluir un ciclo de producción, por viabilidad económica o para conservar la fuente laboral. Debe definir el plan, el plazo, el personal, los bienes y los contratos que se mantienen.',
  '191 bis': 'En las quiebras donde se dispuso la continuación de la empresa a cargo de los trabajadores organizados en cooperativa, el Estado debe brindarles la asistencia técnica necesaria para seguir con el giro de los negocios.',
  '192': 'Régimen de la continuación: el responsable (síndico, coadministrador o cooperativa) puede hacer los actos de administración ordinaria; los que exceden requieren autorización judicial. Las obligaciones que contraiga tienen preferencia. El juez puede terminar la explotación antes de tiempo si resulta deficitaria.',
  '193': 'En la continuación de la empresa (o venta en bloque) se mantienen los contratos de locación en sus condiciones, y el concurso responde por los alquileres futuros. Son nulos los pactos que prevean la resolución del contrato por la sola quiebra.',
  '194': 'Los reclamos que el locador promueva sobre la locación no frenan la explotación de la empresa ni su enajenación; esas circunstancias se tienen en cuenta en las bases de la venta.',
  '195': 'Durante la continuación de la empresa, los acreedores hipotecarios o prendarios no pueden ejecutar los bienes necesarios para la explotación en ciertos casos (créditos no vencidos cuyas cuotas el síndico paga, o sin resolución firme). A pedido de la cooperativa, el juez puede suspender esas ejecuciones hasta 2 años.',
  '196': 'La quiebra NO disuelve el contrato de trabajo: lo suspende de pleno derecho por 60 días corridos. Si vencido ese plazo no se decidió continuar la empresa, el contrato queda disuelto a la fecha de la quiebra y el trabajador verifica sus créditos. Si se continúa, el contrato se reconduce.',
  '197': 'Decidida la continuación, el síndico tiene 10 días para definir qué trabajadores cesan por la reorganización de tareas. Los despedidos tienen derecho a verificar en la quiebra; se considera que la relación terminó por quiebra.',
  '198': 'Los sueldos y retribuciones que se devenguen durante la continuación los paga el concurso en término, como gastos del juicio (preferencia del art. 240). El despido por el síndico, el cierre o la venta de la empresa resuelven definitivamente el contrato.',
  '199': 'El que adquiere la empresa cuya explotación continuó solo es sucesor respecto de los derechos laborales de los trabajadores cuya relación se mantuvo en ese período. Las deudas laborales anteriores a la quiebra se verifican o pagan en el concurso, no las hereda el comprador.',
  // CAPÍTULO V — Período informativo en la quiebra (arts. 200-202)
  '200': 'Igual que en el concurso preventivo (art. 32): todos los acreedores anteriores a la quiebra deben pedir al síndico la verificación de sus créditos, por escrito, indicando monto, causa y privilegio. Se paga un arancel (exentos los créditos laborales y los menores a 3 salarios mínimos) y hay un período de observación.',
  '201': 'El síndico promueve la constitución del comité de control que vigilará la etapa de liquidación, comunicándolo a los trabajadores y a los acreedores verificados, que designan a sus integrantes por mayoría de capital.',
  '202': 'En la "quiebra indirecta" (la que sigue al fracaso de un concurso preventivo), los acreedores posteriores a la presentación verifican por incidente; los que ya habían verificado en el concurso no necesitan hacerlo de nuevo (el síndico recalcula sus créditos).',
  // CAPÍTULO VI — Liquidación y distribución (arts. 203-224)
  '203': 'La realización (venta) de los bienes la hace el síndico y debe comenzar de inmediato, salvo que haya un recurso de reposición contra la quiebra, se haya admitido la conversión en concurso preventivo, o se haya resuelto continuar la explotación.',
  '203 bis': 'Los trabajadores reunidos en cooperativa pueden solicitar la adquisición de la empresa y compensar el precio con los créditos laborales que les corresponden (indemnizaciones), incluso los que otros trabajadores les cedan voluntariamente en audiencia.',
  '204': 'La venta debe hacerse de la forma más conveniente, en este orden de preferencia: primero la empresa como unidad en marcha; luego el establecimiento en conjunto; y por último la venta de los bienes por separado.',
  '205': 'Detalla el procedimiento para vender la empresa o un establecimiento: tasación, posibilidad de oferta de la cooperativa de trabajo, pliego de condiciones, edictos, ofertas en sobre cerrado con garantía del 10%, apertura ante el juez y adjudicación, ponderando especialmente la continuidad de la explotación y la fuente de trabajo.',
  '206': 'Si en la venta se incluyen bienes hipotecados, prendados o con privilegio especial, esas preferencias se trasladan de pleno derecho al precio obtenido, que no puede ser inferior a la suma de esos créditos.',
  '207': 'Si conviene para una mejor realización, el síndico puede proponer vender por separado los bienes gravados, o desinteresar (pagar) a los acreedores privilegiados con fondos del concurso o de quien quiera subrogarse.',
  '208': 'La venta de bienes por separado ("venta singular") se hace por subasta, con edictos (2 a 5 días para muebles, 5 a 10 para inmuebles), sin tasación previa ni base.',
  '209': 'El "concurso especial": los acreedores con garantía real (hipoteca, prenda) pueden pedir la venta del bien garantizado por un expediente separado, cobrando su crédito con privilegio sobre lo obtenido, reservadas las sumas de acreedores preferentes.',
  '210': 'A la ejecución por remate no judicial en la quiebra se le aplica lo dispuesto en el art. 24 (suspensión de remates).',
  '211': 'El que adquiere un bien en la liquidación y a la vez es acreedor no puede compensar el precio con su crédito, salvo que tenga garantía real sobre ese mismo bien (y prestando fianza de acreedor de mejor derecho).',
  '212': 'Se admiten ofertas bajo sobre, presentadas al juzgado al menos 2 días antes de la subasta, que se abren al iniciarse el remate.',
  '213': 'El juez puede disponer la venta directa de bienes (a la cooperativa de trabajo continuadora, o de bienes de escaso valor o cuando fracasó otra forma de venta), cuando resulte de utilidad evidente para el concurso, con aprobación judicial posterior.',
  '214': 'Los bienes que no se puedan vender o cuya venta sea infructuosa, el juez puede entregarlos a asociaciones de bien público, con vista al síndico y al deudor.',
  '215': 'Los títulos cotizables en bolsa y los bienes con precio determinado por oferta pública o con precios oficiales se venden en las instituciones correspondientes (mercados de valores, etc.).',
  '216': 'Los créditos a favor de la quiebra se realizan como prevé el art. 182. El síndico puede encomendar el cobro a bancos o, en circunstancias especiales y con autorización, subastar los créditos o venderlos en cartera.',
  '217': 'Las enajenaciones deben hacerse dentro de los 4 meses de la quiebra (ampliables 90 días). Si no se cumplen los plazos, el síndico y el martillero son removidos automáticamente, y para el juez puede ser causal de mal desempeño.',
  '218': 'Diez días después de la última venta, el síndico presenta el informe final: rendición de cuentas, resultado de la liquidación, bienes no vendidos y el proyecto de distribución final entre los acreedores según sus privilegios. Se regulan honorarios y se publican edictos; el fallido y los acreedores pueden observarlo.',
  '219': 'Las publicaciones del informe final pueden reemplazarse por notificación personal o por cédula a los acreedores, cuando su número o el ahorro de gastos lo aconsejen.',
  '220': 'Siempre deben reservarse fondos para: los acreedores cuyo crédito está sujeto a una condición suspensiva, y los que están pendientes de una resolución judicial o administrativa.',
  '221': 'Aprobado el estado de distribución, se paga a cada acreedor el dividendo que le corresponde, que puede abonarse directamente por el banco de depósitos judiciales o por transferencia.',
  '222': 'Lo que ingrese después del informe final (bienes que no se habían vendido, reservas que se liberan, nuevos fondos) se distribuye directamente, sin trámite previo, según la propuesta del síndico aprobada por el juez.',
  '223': 'Los acreedores que se presentan a verificar después del proyecto de distribución final solo tienen derecho a participar de las distribuciones complementarias futuras, por la parte de su crédito no percibida.',
  '224': 'El derecho del acreedor a cobrar su dividendo caduca al año de aprobada la distribución. La caducidad opera de pleno derecho y los importes no cobrados se destinan al Estado para el fomento de la educación común.',
  // CAPÍTULO VII — Conclusión de la quiebra (arts. 225-229)
  '225': 'El "avenimiento": el deudor puede pedir que se concluya su quiebra si TODOS los acreedores verificados están de acuerdo (con firmas autenticadas). Puede pedirlo desde la verificación y hasta la última venta de bienes.',
  '226': 'El pedido de avenimiento solo interrumpe el trámite si se cumplen todos los requisitos. El juez puede exigir un depósito para los acreedores verificados que no puedan ser hallados y los pendientes de resolución, y una garantía por los gastos.',
  '227': 'El avenimiento hace cesar todos los efectos patrimoniales de la quiebra (el deudor recupera su patrimonio), aunque siguen siendo válidos los actos ya cumplidos por el síndico. Si el deudor no cumple lo que acordó con los acreedores, no se reabre la quiebra (sí pueden pedir una nueva).',
  '228': 'Conclusión por "pago total": si los bienes alcanzan para pagar a todos los acreedores verificados, los pendientes y los gastos, se declara concluida la quiebra. Si sobra dinero, se pagan los intereses que se habían suspendido y el saldo se le devuelve al deudor.',
  '229': 'La conclusión por pago total también procede cuando se agrega la carta de pago de todos los acreedores y se cubren los gastos, o cuando ningún acreedor se presentó a verificar y se pagan los gastos del concurso.',
  // CAPÍTULO VIII — Clausura del procedimiento (arts. 230-233)
  '230': 'Clausura por distribución final: realizado todo el activo y hecha la distribución, el juez clausura el procedimiento. La clausura no impide que sigan produciéndose los efectos de la quiebra.',
  '231': 'El procedimiento clausurado puede reabrirse si aparecen bienes que se puedan desapoderar. Pasados 2 años desde la clausura sin que se reabra, el juez puede declarar concluido el concurso definitivamente.',
  '232': 'Clausura por falta de activo: si, hecha la verificación, no hay activo suficiente ni para pagar los gastos del juicio (incluidos los honorarios), el juez debe clausurar el procedimiento por falta de activo, a pedido del síndico y con vista al fallido.',
  '233': 'La clausura por falta de activo hace presumir que hubo fraude: el juez debe comunicarla a la justicia penal para que se instruya el sumario correspondiente.',
  // CAPÍTULO IX — Inhabilitación del fallido (arts. 234-238)
  '234': 'El fallido queda "inhabilitado" desde la fecha de la quiebra (sufre las restricciones del art. 238 para ejercer el comercio y administrar sociedades).',
  '235': 'En la quiebra de una persona jurídica, la inhabilitación se extiende a las personas físicas que integraron sus órganos de administración desde la cesación de pagos. Para los que ya no estaban a la fecha de la quiebra, rige desde que queda firme la fecha de cesación de pagos.',
  '236': 'La inhabilitación cesa de pleno derecho al año de la sentencia de quiebra (o de fijada la cesación de pagos). El juez puede reducirla si el inhabilitado no parece incurso en delito. Se prorroga si hay proceso penal: dura hasta el sobreseimiento, absolución o cumplimiento de la condena.',
  '237': 'La inhabilitación de las personas jurídicas es definitiva, salvo que se admita la conversión en concurso preventivo (art. 90) o se concluya la quiebra.',
  '238': 'El inhabilitado no puede ejercer el comercio (por sí ni por interpósita persona), ni ser administrador, gerente, síndico, liquidador o fundador de sociedades, asociaciones, mutuales o fundaciones, ni integrar sociedades o ser apoderado con facultades generales.',

  // ─── TÍTULO IV — Disposiciones complementarias ──────────────────────────────
  // CAPÍTULO I — Privilegios (arts. 239-250)
  '239': 'En un concurso, solo tienen privilegio (prioridad de cobro) los créditos que esta ley enumera. Los privilegios reconocidos en el concurso preventivo mantienen su graduación en la quiebra posterior. Es la regla base del orden de cobro.',
  '240': 'Los "gastos de conservación y de justicia": los créditos generados por conservar, administrar y liquidar los bienes y por el trámite del concurso se pagan ANTES que los créditos contra el deudor (salvo los de privilegio especial), apenas son exigibles y sin necesidad de verificar. Es la preferencia que se cita en toda la ley.',
  '241': 'Enumera los créditos con "privilegio especial", que cobran con prioridad sobre el producido de un bien determinado: gastos de construcción o mejora de una cosa; los créditos laborales (6 meses de sueldo e indemnizaciones) sobre las mercaderías y maquinarias; los impuestos sobre el bien gravado; los garantizados con hipoteca, prenda o warrant; el del retenedor; y ciertos créditos marítimos, aeronáuticos y de seguros.',
  '242': 'El privilegio especial cubre solo el capital del crédito, salvo: los intereses de 2 años de los créditos laborales (inc. 2), y las costas e intereses (anteriores y posteriores a la quiebra) de los créditos con garantía real (inc. 4).',
  '243': 'Los privilegios especiales cobran en el orden en que aparecen sus incisos en el art. 241, salvo los de garantía real (que se rigen por sus propias leyes) y el del retenedor (que prevalece si la retención empezó antes). Si concurren varios del mismo inciso sobre el mismo bien, cobran a prorrata.',
  '244': 'Antes de pagar a los acreedores con privilegio especial, se reserva del precio del bien lo gastado en su conservación, custodia, administración y venta, más una parte para los honorarios de los funcionarios por las diligencias sobre ese bien.',
  '245': 'El privilegio especial se traslada de pleno derecho a lo que reemplace al bien (indemnización del seguro, precio de venta, etc.). Lo que exceda de esos importes se considera crédito común (quirografario).',
  '246': 'Enumera los créditos con "privilegio general" (cobran sobre todo el activo, no sobre un bien puntual): los laborales (6 meses de sueldo, indemnizaciones, vacaciones, aguinaldo, intereses de 2 años); los de la seguridad social; si el deudor es persona humana, ciertos gastos funerarios, de enfermedad y de necesidad; los impuestos; y las facturas de crédito hasta cierto monto.',
  '247': 'Los créditos con privilegio general solo pueden afectar la mitad del producto líquido de los bienes (tras pagar los privilegios especiales, los gastos del art. 240 y los sueldos del art. 246 inc. 1). Por lo que exceda esa mitad, concurren a prorrata con los quirografarios.',
  '248': 'Los créditos a los que la ley no reconoce ningún privilegio son "comunes" o "quirografarios": cobran al final, después de todos los privilegiados.',
  '249': 'Si los fondos no alcanzan para pagar íntegramente a los créditos con privilegio general, se reparten a prorrata entre ellos. La misma regla rige para los quirografarios.',
  '250': 'Los "créditos subordinados": si un acreedor pactó con el deudor postergar el cobro de su crédito respecto de otras deudas, ese crédito se rige por las condiciones de la subordinación acordada (cobra después).',
  // CAPÍTULO II — Funcionarios y empleados de los concursos (arts. 251-272)
  '251': 'Los funcionarios del concurso son: el síndico, el coadministrador y los controladores del cumplimiento del acuerdo preventivo y de la liquidación en la quiebra.',
  '252': 'Las funciones de cada funcionario son indelegables (no puede pasárselas a otro) y excluyentes de la actuación del deudor y de los acreedores, salvo donde la ley prevé expresamente su participación o el derecho a denunciar la actuación de los funcionarios.',
  '253': 'Designación del síndico: pueden inscribirse contadores con al menos 5 años de matrícula (o estudios contables). Cada 4 años la Cámara forma listas (estudios y profesionales individuales) y el juez designa por sorteo público. En procesos complejos puede haber sindicatura plural (varios síndicos).',
  '254': 'El síndico cumple sus funciones durante todo el concurso preventivo hasta su finalización, y en todo el proceso de quiebra, incluida su liquidación.',
  '255': 'El síndico no puede renunciar a las designaciones salvo causa grave. Se lo remueve por negligencia, falta grave o mal desempeño; la remoción lo inhabilita para el cargo entre 4 y 10 años y puede reducirle los honorarios. También puede recibir apercibimiento o multa.',
  '256': 'No puede ser síndico quien esté respecto del fallido en una situación que permitiría recusar a un juez (parentesco, enemistad, etc.). Es falta grave que el síndico no se excuse dentro de los 5 días de conocida la causal.',
  '257': 'El síndico puede pedir asesoramiento profesional cuando el tema excede su competencia, y tener patrocinio letrado, pero los honorarios de esos profesionales corren por su exclusiva cuenta.',
  '258': 'El síndico debe actuar personalmente. Si es un estudio, debe indicar en cada concurso qué profesional asume actuar personalmente, y no puede reemplazarlo salvo causa justificada admitida por el juez.',
  '259': 'Los coadministradores actúan en la continuación de la explotación de la empresa (arts. 192 a 199). Deben ser personas especializadas en el ramo o graduados en administración de empresas. Su remoción se rige por el art. 255.',
  '260': 'El comité de control es un órgano que representa a los acreedores y trabajadores: el provisorio informa y aconseja; el definitivo es el controlador necesario del cumplimiento del acuerdo preventivo y de la liquidación en la quiebra.',
  '261': 'La venta de los activos de la quiebra puede encargarse a martilleros, bancos, intermediarios profesionales o entidades especializadas. El martillero lo designa el juez, debe tener casa abierta al público y 6 años de matrícula, y cobra comisión solo del comprador.',
  '262': 'La valuación de las acciones o cuotas en el salvataje del art. 48 la hacen bancos de inversión, entidades financieras o estudios de auditoría con más de 10 años. La Cámara forma una lista cada 4 años; el comité propone una terna y el juez elige.',
  '263': 'El síndico puede pedir al juez autorización para contratar empleados, en el número y por el tiempo necesarios para hacer sus tareas de forma eficaz y económica.',
  '264': 'Salvo servicios mensuales u operaciones por monto fijo, no se puede sacar dinero del concurso para pagos a cuenta de servicios continuados cuya remuneración dependa de una estimación judicial.',
  // SECCIÓN II — Regulación de honorarios (arts. 265-272)
  '265': 'El juez regula los honorarios de los funcionarios en estos momentos: al homologar el acuerdo preventivo, al sobreseer por avenimiento, al aprobar cada distribución, al finalizar la venta de bienes y al concluir el proceso por cualquier causa.',
  '266': 'En el acuerdo preventivo, los honorarios totales (funcionarios y letrados del síndico y del deudor) se regulan sobre el activo estimado, entre el 1% y el 4%, sin superar el 4% del pasivo verificado ni bajar de 2 sueldos de secretario. Si el activo supera $100 millones, el tope es el 1%.',
  '267': 'En la quiebra liquidada, los honorarios se regulan sobre el activo realizado: no menos del 4% (ni de 3 sueldos de secretario) ni más del 12% del activo realizado.',
  '268': 'Al concluir o clausurar: por pago total se aplica el art. 267; por falta de activo o sin acreedores verificados, se regula según la labor realizada, pudiendo consumir todos los fondos existentes tras los privilegios especiales y demás gastos.',
  '269': 'En caso de continuación de la empresa, además de los honorarios comunes, se regula para el síndico y el coadministrador hasta un 10% del resultado neto de la explotación (sin contar el precio de venta de los bienes del inventario).',
  '270': 'Como alternativa a lo anterior, el juez puede, por auto fundado, fijar al coadministrador una suma determinada o pagos por períodos. El coadministrador solo cobra honorarios por estos artículos, sin participar del producto de los bienes.',
  '271': 'Para calcular estos honorarios no se aplican las leyes arancelarias locales. El juez puede apartarse de los mínimos de esta ley cuando aplicarlos sin más llevaría a una desproporción con el trabajo realizado, fundando explícitamente esa decisión.',
  '272': 'Las regulaciones de honorarios son apelables por su titular y por el síndico (y por el deudor en ciertos casos). En los demás, el juez debe remitir el expediente a la Cámara, que puede reducir las regulaciones aunque el síndico no haya apelado.',
  // CAPÍTULO III — Reglas procesales (arts. 273-287)
  '273': 'Principios procesales del concurso: todos los plazos son perentorios y, si no se fijó otro, de 5 días hábiles judiciales; por regla las resoluciones son inapelables (y cuando se admite apelación, es con efecto suspensivo); no se remite el expediente a otro juzgado; muchas anotaciones registrales no requieren pago previo de tasas.',
  '274': 'El juez dirige el proceso y puede dictar todas las medidas de impulso e investigación necesarias: por ejemplo, ordenar la comparecencia del concursado (incluso con la fuerza pública) y la presentación de documentos que tengan el concursado o terceros.',
  '275': 'Enumera las facultades del síndico para impulsar la causa e investigar el patrimonio: librar cédulas y oficios, pedir informes a entidades públicas y privadas, requerir explicaciones, examinar expedientes sin autorización, tener oficina abierta al público y dar recibo de los escritos. El síndico es parte en el proceso y sus incidentes.',
  '276': 'El ministerio fiscal interviene como parte ante la Cámara (alzada) en los supuestos del art. 51 y, en las quiebras, cuando se concedió un recurso en que el síndico sea parte.',
  '277': 'En el proceso concursal principal no opera la perención (caducidad) de instancia. En las demás actuaciones y en cualquier instancia, la perención se produce a los 3 meses.',
  '278': 'En lo que esta ley no prevea expresamente, se aplican las normas procesales del lugar del juicio, siempre que sean compatibles con la rapidez y economía propias del trámite concursal.',
  '279': 'Se forma un "legajo de copias" con todas las actuaciones fundamentales del juicio, que debe estar siempre a disposición de los interesados en secretaría. Es falta grave del secretario no mantenerlo actualizado.',
  // SECCIÓN II — Incidentes (arts. 280-287)
  '280': 'Toda cuestión que tenga relación con el concurso y no tenga un procedimiento especial propio tramita como "incidente", en una pieza (expediente) separada, según las reglas de este capítulo.',
  '281': 'En el escrito que plantea el incidente hay que ofrecer toda la prueba y acompañar los documentos. Si el juez lo ve manifiestamente improcedente, lo rechaza sin más. Si lo admite, da traslado por 10 días notificado por cédula.',
  '282': 'La prueba del incidente se diligencia en el plazo que fije el juez, dentro de un máximo de 20 días. Las partes deben urgir su producción; el juez puede resolver vencido el plazo aunque la prueba no esté completa, si la considera innecesaria.',
  '283': 'La prueba pericial se hace con un solo perito designado de oficio, salvo que por la naturaleza del asunto el juez designe tres (en cuyo caso las partes pueden proponer dos que actúan con el primero).',
  '284': 'No se admiten más de 5 testigos por cada parte; solo se acepta un número mayor, ofrecido junto con la demás prueba, cuando la complejidad de la causa lo justifique.',
  '285': 'Dentro del incidente, solo es apelable la resolución que le pone fin. Las decisiones intermedias o que niegan una prueba pueden cuestionarse ante la Cámara al apelar esa resolución final.',
  '286': 'Todas las cuestiones incidentales cuyas causas existan a la vez y sean conocidas por quien las promueve deben plantearse juntas. Las que se entablen después se desestiman sin más trámite.',
  '287': 'En los incidentes de revisión y de verificación tardía de créditos, los honorarios se regulan según las leyes arancelarias locales para incidentes, tomando como monto del juicio el del propio crédito insinuado y verificado.',
  // CAPÍTULO IV — De los pequeños concursos y quiebras (arts. 288-297)
  '288': 'Se consideran "pequeños concursos y quiebras" aquellos en los que se dé cualquiera de estas circunstancias: pasivo denunciado menor a 300 salarios mínimos, no más de 20 acreedores quirografarios, o no más de 20 trabajadores en relación de dependencia.',
  '289': 'En los pequeños concursos se simplifica el trámite: no hacen falta ciertos dictámenes del art. 11, ni constituir comités de acreedores, ni rige el salvataje del art. 48. El síndico controla el cumplimiento del acuerdo (con honorarios del 1% de lo pagado a los acreedores).',
  '290': 'Artículo vetado por el Poder Ejecutivo al promulgar la ley (Decreto 267/1995): no forma parte del texto vigente.',
  '291': 'Dentro de los 30 días de publicada la ley, las Cámaras de Apelaciones debían abrir los registros de síndicos, enajenadores y evaluadores previstos en los arts. 253, 261 y 262. Es una norma de implementación inicial.',
  '292': 'Desde la entrada en vigor de la ley, sus normas sobre regulación de honorarios se aplican también a los concursos y quiebras que ya estaban en trámite (con una salvedad respecto de la ley anterior 19.551).',
  '293': 'La Ley de Concursos y Quiebras se incorpora como Libro IV del Código de Comercio y deroga la ley anterior (19.551), algunos artículos de la Ley de Contrato de Trabajo y de la Ley de Sociedades, y toda norma que se le oponga.',
  '295': 'Crea el Registro Nacional de Concursos y Quiebras, donde los jueces de todo el país (nacionales y provinciales) deben informar, dentro de los 5 días, los procesos concursales que tramiten y sus modificaciones relevantes.',
  '296': 'Faculta al Poder Ejecutivo Nacional a reglamentar el funcionamiento y la organización del Registro Nacional de Concursos y Quiebras.',
  '297': 'Fórmula final de comunicación de la ley al Poder Ejecutivo Nacional, con las firmas de las autoridades del Congreso (sanción del 20 de julio de 1995).',
};

